                  </div>
                  <div>
                    <label style={S.label}>Confirm Password</label>
                    <input style={S.input} type="password" value={staffPw2}
                      onChange={e => { setStaffPw2(e.target.value); setStaffMsg(null); }}
                      placeholder="Re-enter password" autoComplete="new-password" />
