                  {v < 0 ? `-${fmt(-v)}` : fmt(v)}
                </span>
              </div>
            ))}
            <EventCostLedger
              evt={evt}
              inventory={inventory || []}
              onUpdate={(lines) => updateCostLines(evt.id, lines)}
            />
            <Divider />
            {/* Media section in side panel */}
            <PhasedMediaGallery
              media={evt.media || []}
              onAdd={(m) => addMedia(evt.id, m)}
              onDelete={(mid) => deleteMedia(evt.id, mid)}
              onUpdate={(mid, patch) => updateMedia(evt.id, mid, patch)}
              currentPhase={evt.phase}
            />
            <Divider />
            {/* Linked Proposals section */}
            {(() => {
              const linked = (proposals || []).filter((p) => p.eventId === evt.id);
              return (
                <div style={{ marginBottom: 8 }}>
                  <div style={{ fontSize: 10, fontWeight: 700, color: T.textMuted, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: linked.length ? 7 : 4 }}>
                    📋 Linked Proposals ({linked.length})
                  </div>
                  {linked.length === 0 ? (
                    <div style={{ fontSize: 11, color: T.textDim }}>No proposals linked. Go to Proposals to link or convert one.</div>
                  ) : (
                    linked.map((p) => (
                      <div key={p.id} style={{ background: T.surface, borderRadius: 7, padding: "7px 10px", marginBottom: 5, border: `1px solid ${T.border}` }}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                          <div>
                            <div style={{ fontSize: 11, fontWeight: 700 }}>{p.num}</div>
                            <div style={{ fontSize: 10, color: T.textMuted }}>{p.lines?.length || 0} items · {fmt(propTotal(p.lines, p.discount))}</div>
                          </div>
                          <Badge color={{ Draft: T.textMuted, Sent: T.info, Approved: T.success, "Converted to Event": T.catering, Declined: T.danger }[p.status] || T.textMuted}>
                            {p.status}
                          </Badge>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              );
            })()}
            <Divider />
            {/* ── Payment Status & Recording ── */}
            {(() => {
              const linkedInv = (invoices || []).find(inv => inv.eventId === evt.id);
              if (!linkedInv) {
                return (
                  <div style={{ marginBottom: 8 }}>
                    <div style={{ fontSize: 10, fontWeight: 700, color: T.textMuted, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 6 }}>💰 Payment</div>
                    <div style={{ fontSize: 11, color: T.textDim }}>No invoice linked. Use the Invoice button below to generate one, or approve a proposal to auto-create it.</div>
                  </div>
                );
              }
              const bal = linkedInv.total - linkedInv.paid;
              const isPaid = bal <= 0;
              const stColor = isPaid ? T.success : linkedInv.paid > 0 ? T.warning : T.danger;
              const stLabel = isPaid ? "Fully Paid" : linkedInv.paid > 0 ? "Partially Paid" : "Unpaid";
              return (
                <div style={{ marginBottom: 10 }}>
                  <div style={{ fontSize: 10, fontWeight: 700, color: T.textMuted, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 8 }}>💰 Payment — {linkedInv.num}</div>
                  {/* Status bar */}
                  <div style={{ background: T.surface, borderRadius: 8, padding: "8px 10px", marginBottom: 8, border: `1px solid ${stColor}40` }}>
                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 5 }}>
                      <span style={{ fontSize: 10, color: T.textMuted }}>Invoice Total</span>
                      <span style={{ fontSize: 12, fontWeight: 700 }}>{fmt(linkedInv.total)}</span>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 5 }}>
                      <span style={{ fontSize: 10, color: T.textMuted }}>Paid</span>
                      <span style={{ fontSize: 12, fontWeight: 700, color: T.success }}>{fmt(linkedInv.paid)}</span>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between", paddingTop: 5, borderTop: `1px solid ${T.border}` }}>
                      <span style={{ fontSize: 10, fontWeight: 700, color: stColor }}>Balance Due</span>
                      <span style={{ fontSize: 13, fontWeight: 800, color: stColor }}>{fmt(bal)}</span>
                    </div>
                    {/* Progress bar */}
                    <div style={{ height: 4, borderRadius: 2, background: T.border, marginTop: 7, overflow: "hidden" }}>
                      <div style={{ height: "100%", width: `${Math.min(100, linkedInv.total > 0 ? (linkedInv.paid / linkedInv.total) * 100 : 0)}%`, background: stColor, borderRadius: 2, transition: "width 0.3s" }} />
                    </div>
                    <div style={{ fontSize: 9, color: stColor, fontWeight: 700, marginTop: 4 }}>{stLabel}</div>
                  </div>
                  {/* Record payment */}
                  {!isPaid && (
                    <EventPaymentRecorder linkedInv={linkedInv} bal={bal} setInvoices={setInvoices} />
                  )}
                </div>
              );
            })()}
            <Divider />
            <div style={{ display: "flex", gap: 5, flexWrap: "wrap" }}>
              <button
                style={{
                  ...S.btn("primary"),
                  fontSize: 10,
                  padding: "4px 9px",
                }}
                onClick={() => {
                  const inv = {
                    num: `INV-${THIS_YEAR}-${String(evt.id).padStart(4, "0")}`,
                    client: evt.clientName,
                    clientPhone: evt.clientPhone,
                    issued: evt.eventDate,
                    due: evt.eventDate,
                    total: evt.revenue,
                    paid: 0,
                    status: "Unpaid",
                    notes: "",
                  };
                  openDoc(
                    `Invoice – ${evt.name}`,
                    buildInvoiceHTML(inv, evt, biz, logo)
                  );
                }}
              >
                📄 Invoice
              </button>
              <button
                style={{ ...S.btn("ghost"), fontSize: 10, padding: "4px 9px" }}
                onClick={() => {
                  const inv = {
                    num: `INV-${THIS_YEAR}-${String(evt.id).padStart(4, "0")}`,
                    client: evt.clientName,
                    clientPhone: evt.clientPhone,
                    issued: evt.eventDate,
                    due: evt.eventDate,
                    total: evt.revenue,
                    paid: evt.revenue,
                    status: "Paid",
                    notes: "",
                  };
                  openDoc(
                    `Receipt – ${evt.name}`,
                    buildReceiptHTML(inv, biz, logo)
                  );
                }}
              >
                🧾 Receipt
              </button>
              <button
                style={{ ...S.btn("ghost"), fontSize: 10, padding: "4px 9px", color: T.danger, borderColor: T.danger + "40", marginLeft: "auto" }}
                onClick={() => deleteEvent(evt.id)}
              >
                🗑 Delete Event
              </button>
            </div>
            {evt.notes && (
              <div
                style={{
                  fontSize: 10,
                  color: T.textMuted,
                  background: T.surface,
                  padding: 7,
                  borderRadius: 5,
                  marginTop: 7,
                }}
              >
                {evt.notes}
              </div>
            )}
          </div>
        )}
      </div>
    </>)}
    </div>
  );
}
function CatalogPage({ categories, setCategories, items, setItems, meals, logo, biz, onCreateProposalFromCatalog }) {
  const [selCat, setSelCat] = useState(null); // null = tile overview, number = category id
  const [adding, setAdding] = useState(false);
  const [editId, setEditId] = useState(null);
  const [addingCat, setAddingCat] = useState(false);
  const [newCatName, setNewCatName] = useState("");
  const [search, setSearch] = useState("");
  const EMPTY_NI = { catId: categories[0]?.id || 1, name: "", unitType: "Per head", price: "", costPerUnit: "", tags: "", description: "", notes: "", photo: null };
  const [ni, setNi] = useState(EMPTY_NI);
  const [doc, setDoc] = useState(null);
  const photoRef = useRef();

  const filtered = selCat
    ? items.filter(i => i.catId === selCat && (!search || i.name.toLowerCase().includes(search.toLowerCase())))
    : items.filter(i => !search || i.name.toLowerCase().includes(search.toLowerCase()));

  const handlePhoto = async (e, forItem = null) => {
    const f = e.target.files[0]; if (!f) return;
    // Try Storage first — keeps base64 out of the database for catalog photos
    const storageUrl = await uploadToStorage(f, "catalog");
    if (storageUrl) {
      if (forItem != null) setItems(prev => prev.map(it => it.id === forItem ? { ...it, photo: storageUrl } : it));
      else setNi(n => ({ ...n, photo: storageUrl }));
    } else {
      // Fallback to base64
      const r = new FileReader();
      r.onload = (ev) => {
        if (forItem != null) setItems(prev => prev.map(it => it.id === forItem ? { ...it, photo: ev.target.result } : it));
        else setNi(n => ({ ...n, photo: ev.target.result }));
      };
      r.readAsDataURL(f);
    }
  };

  const pullFromMeal = (mealId) => {
    if (!mealId) return;
    const m = meals.find(ml => String(ml.id) === String(mealId));
    if (!m) return;
    setNi(prev => ({
      ...prev,
      name: m.name || prev.name,
      price: m.price ? String(m.price) : prev.price,
      description: m.description || prev.description,
      photo: m.photo || prev.photo,
      unitType: "Per head",
    }));
  };

  const save = () => {
    if (!ni.name || !ni.price) return;
    const item = {
      ...ni,
      price: Number(ni.price),
      costPerUnit: Number(ni.costPerUnit) || 0,
      tags: typeof ni.tags === "string" ? ni.tags.split(",").map(t => t.trim()).filter(Boolean) : ni.tags,
    };
    if (editId != null) {
      setItems(prev => prev.map(it => {
        if (it.id !== editId) return it;
        // Never overwrite an existing photo with null — only update if a new one was uploaded
        const photo = item.photo !== null ? item.photo : it.photo;
        return { ...item, id: editId, photo };
      }));
      setEditId(null);
    } else {
      setItems(prev => [...prev, { ...item, id: Date.now() }]);
    }
    setAdding(false);
    setNi({ ...EMPTY_NI, catId: selCat || (categories[0]?.id || 1) });
  };

  const startEdit = (item) => {
    setNi({ ...item, price: String(item.price), costPerUnit: String(item.costPerUnit || ""), tags: Array.isArray(item.tags) ? item.tags.join(", ") : item.tags });
    setEditId(item.id);
    setAdding(true);
    // Navigate into the item's category so the form is visible
    if (!selCat) setSelCat(item.catId);
  };

  const addCategory = () => {
    const name = newCatName.trim(); if (!name) return;
    const newId = Math.max(0, ...categories.map(c => c.id)) + 1;
    setCategories(prev => [...prev, { id: newId, name }]);
    setNewCatName(""); setAddingCat(false);
  };

  const deleteCategory = (id) => {
    if (items.some(i => i.catId === id)) { alert("Remove all items in this category first."); return; }
    setCategories(prev => prev.filter(c => c.id !== id));
    if (selCat === id) setSelCat(null);
  };

  const openDoc = (title, html) => setDoc({ title, html, onPrint: () => printDoc(title, html) });
  const selCatObj = categories.find(c => c.id === selCat);

  return (
    <div>
      <DocModal doc={doc} onClose={() => setDoc(null)} />
      <div style={{ ...S.row, marginBottom: 4 }}>
        <div>
          <div style={S.pageTitle}>📦 Catering Catalog</div>
          <div style={S.subtitle}>{items.length} items across {categories.length} categories</div>
        </div>
        <button style={S.btn("primary")} onClick={() => openDoc("Services Catalog", buildCatalogHTML(items, categories, biz, logo))}>
          🖨️ Print Catalog
        </button>
      </div>

      {/* ── CATEGORY TILES VIEW ── */}
      {!selCat && (
        <div>
          <div style={{ ...S.row, marginBottom: 14, gap: 8, flexWrap: "wrap" }}>
            <input style={{ ...S.input, flex: 1, minWidth: 160 }} placeholder="Search all items…" value={search} onChange={e => setSearch(e.target.value)} />
            {!addingCat
              ? <button style={{ ...S.btn("ghost"), fontSize: 12 }} onClick={() => setAddingCat(true)}>＋ New Category</button>
              : <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
                  <input style={{ ...S.input, width: 180, marginBottom: 0 }} placeholder="e.g. 🍱 Meal Boxes" value={newCatName} onChange={e => setNewCatName(e.target.value)} onKeyDown={e => e.key === "Enter" && addCategory()} autoFocus />
                  <button style={S.btn("primary")} onClick={addCategory}>Add</button>
                  <button style={S.btn("ghost")} onClick={() => { setAddingCat(false); setNewCatName(""); }}>✕</button>
                </div>
            }
          </div>

          {search ? (
            // Search results across all categories
            <div>
              <div style={{ fontSize: 12, color: T.textMuted, marginBottom: 10 }}>{filtered.length} results for "{search}"</div>
              <div style={S.grid(3)}>
                {filtered.map(item => <CatalogItemCard key={item.id} item={item} categories={categories} setItems={setItems} startEdit={startEdit} handlePhoto={handlePhoto} />)}
              </div>
            </div>
          ) : (
            // Category tiles
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(160px, 1fr))", gap: 10 }}>
              {categories.map(cat => {
                const catItems = items.filter(i => i.catId === cat.id);
                const thumb = catItems.find(i => i.photo)?.photo;
                return (
                  <div key={cat.id} style={{ ...S.card, padding: 0, overflow: "hidden", cursor: "pointer", border: `1px solid ${T.border}`, transition: "box-shadow 0.15s" }}
                    onMouseEnter={e => e.currentTarget.style.boxShadow = "0 4px 16px rgba(0,0,0,0.18)"}
                    onMouseLeave={e => e.currentTarget.style.boxShadow = ""}
                    onClick={() => { setSelCat(cat.id); setAdding(false); }}>
                    {/* Tile image */}
                    <div style={{ height: 90, background: T.surface, overflow: "hidden", position: "relative" }}>
                      {thumb
                        ? <img src={thumb} alt={cat.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                        : <div style={{ height: "100%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 32, opacity: 0.5 }}>{cat.name.match(/\p{Emoji}/u)?.[0] || "🍽️"}</div>
                      }
                      {catItems.length > 0 && (
                        <div style={{ position: "absolute", top: 5, right: 5, background: T.accent, color: "#fff", fontSize: 10, fontWeight: 700, padding: "2px 7px", borderRadius: 10 }}>
                          {catItems.length}
                        </div>
                      )}
                    </div>
                    {/* Tile label */}
                    <div style={{ padding: "8px 10px 6px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                      <div style={{ fontSize: 11, fontWeight: 700, color: T.text, lineHeight: 1.3 }}>{cat.name}</div>
                      <button style={{ background: "none", border: "none", color: T.textDim, cursor: "pointer", fontSize: 13, padding: 2, lineHeight: 1 }}
                        onClick={e => { e.stopPropagation(); deleteCategory(cat.id); }}>🗑</button>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}

      {/* ── CATEGORY DETAIL VIEW ── */}
      {selCat && (
        <div>
          {/* Breadcrumb */}
          <div style={{ ...S.row, marginBottom: 12, gap: 8, flexWrap: "wrap" }}>
            <button style={{ ...S.btn("ghost"), fontSize: 12 }} onClick={() => { setSelCat(null); setAdding(false); setEditId(null); }}>
              ← All Categories
            </button>
            <div style={{ fontSize: 14, fontWeight: 700, color: T.text }}>{selCatObj?.name}</div>
            <div style={{ fontSize: 12, color: T.textMuted }}>({items.filter(i => i.catId === selCat).length} items)</div>
            <div style={{ flex: 1 }} />
            {onCreateProposalFromCatalog && items.filter(i => i.catId === selCat).length > 0 && (
              <button
                style={{ ...S.btn("ghost"), fontSize: 11, padding: "4px 10px", borderColor: T.catering, color: T.catering }}
                title="Open Proposals and pre-fill with all items from this category"
                onClick={() => {
                  const catItems = items.filter(i => i.catId === selCat);
                  const lines = catItems.map(item => ({
                    itemId: item.id,
                    name: item.name,
                    qty: 1,
                    price: item.price,
                    unitType: item.unitType,
                  }));
                  onCreateProposalFromCatalog(lines);
                }}
              >
                🎉 Create Proposal from this Category
              </button>
            )}
            <button style={S.btn("primary")} onClick={() => { setAdding(!adding); setEditId(null); setNi({ ...EMPTY_NI, catId: selCat }); }}>
              {adding && editId == null ? "✕ Cancel" : "+ Add Item"}
            </button>
          </div>

          {/* Add / Edit form */}
          {adding && (
            <div style={{ ...S.card, marginBottom: 14, borderColor: T.accent }}>
              <div style={S.sectionTitle}>{editId != null ? "✏️ Edit Item" : "➕ New Item"}</div>

              {/* Pull from meals */}
              {!editId && meals && meals.length > 0 && (
                <div style={{ background: T.accentSoft, borderRadius: 8, padding: "8px 12px", marginBottom: 12, display: "flex", alignItems: "center", gap: 10 }}>
                  <span style={{ fontSize: 11, color: T.accent, fontWeight: 700, whiteSpace: "nowrap" }}>⚡ Pull from Meals:</span>
                  <select style={{ ...S.select, flex: 1, marginBottom: 0 }} onChange={e => pullFromMeal(e.target.value)} defaultValue="">
                    <option value="">— Select a meal to pre-fill —</option>
                    {meals.map(m => <option key={m.id} value={m.id}>{m.name}{m.price ? ` · ${fmt(m.price)} USD` : ""}</option>)}
                  </select>
                </div>
              )}

              <div style={S.grid(3)}>
                <div>
                  <label style={S.label}>Item Name *</label>
                  <input style={S.input} value={ni.name} onChange={e => setNi({ ...ni, name: e.target.value })} placeholder="e.g. Spicy Chicken Box" />
                </div>
                <div>
                  <label style={S.label}>Category</label>
                  <select style={S.select} value={ni.catId} onChange={e => setNi({ ...ni, catId: Number(e.target.value) })}>
                    {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                </div>
                <div>
                  <label style={S.label}>Unit Type</label>
                  <select style={S.select} value={ni.unitType} onChange={e => setNi({ ...ni, unitType: e.target.value })}>
                    {["Per head","Per tray","Per platter","Per item","Per hour","Per day","Flat fee"].map(u => <option key={u}>{u}</option>)}
                  </select>
                </div>
                <div>
                  <label style={S.label}>Sale Price (USD) *</label>
                  <input style={S.input} type="number" value={ni.price} onChange={e => setNi({ ...ni, price: e.target.value })} />
                </div>
                <div>
                  <label style={S.label}>Cost / Unit (USD)</label>
                  <input style={S.input} type="number" value={ni.costPerUnit} onChange={e => setNi({ ...ni, costPerUnit: e.target.value })} />
                </div>
                <div>
                  <label style={S.label}>Photo</label>
                  <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
                    {ni.photo && <img src={ni.photo} alt="p" style={{ width: 36, height: 36, objectFit: "cover", borderRadius: 4, border: `1px solid ${T.border}` }} />}
                    <button style={{ ...S.btn("ghost"), fontSize: 11, padding: "4px 8px" }} onClick={() => photoRef.current.click()}>{ni.photo ? "Change" : "Upload"}</button>
                    {ni.photo && <button style={{ background: "none", border: "none", color: T.danger, cursor: "pointer", fontSize: 11 }} onClick={() => setNi({ ...ni, photo: null })}>✕</button>}
                    <input ref={photoRef} type="file" accept="image/*" style={{ display: "none" }} onChange={e => handlePhoto(e)} />
                  </div>
                </div>
                <div style={{ gridColumn: "span 3" }}>
                  <label style={S.label}>Description</label>
                  <input style={S.input} value={ni.description} onChange={e => setNi({ ...ni, description: e.target.value })} placeholder="Short description for catalog" />
                </div>
                <div style={{ gridColumn: "span 3" }}>
                  <label style={S.label}>Notes (printed on catalog)</label>
                  <input style={S.input} value={ni.notes || ""} onChange={e => setNi({ ...ni, notes: e.target.value })} placeholder="e.g. Contains nuts · Halal · Minimum 20 portions" />
                </div>
                <div style={{ gridColumn: "span 3" }}>
                  <label style={S.label}>Tags (comma-separated)</label>
                  <input style={S.input} value={ni.tags} onChange={e => setNi({ ...ni, tags: e.target.value })} placeholder="e.g. Buffet, Birthday, Halal" />
                </div>
              </div>
              <div style={{ ...S.row, marginTop: 10, justifyContent: "flex-end" }}>
                <button style={S.btn("ghost")} onClick={() => { setAdding(false); setEditId(null); }}>Cancel</button>
                <button style={S.btn("primary")} onClick={save}>{editId != null ? "Update" : "Save Item"}</button>
              </div>
            </div>
          )}

          {/* Items grid */}
          <div style={S.grid(3)}>
            {filtered.map(item => <CatalogItemCard key={item.id} item={item} categories={categories} setItems={setItems} startEdit={startEdit} handlePhoto={handlePhoto} onDelete={() => setItems(prev => prev.filter(i => i.id !== item.id))} />)}
          </div>
          {filtered.length === 0 && !adding && (
            <div style={{ color: T.textMuted, padding: 40, textAlign: "center", fontSize: 13 }}>
              <div style={{ fontSize: 32, marginBottom: 8 }}>🍽️</div>
              No items in this category yet.<br />
              <span style={{ color: T.accent, cursor: "pointer" }} onClick={() => { setAdding(true); setNi({ ...EMPTY_NI, catId: selCat }); }}>+ Add the first item</span>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ─── CATALOG ITEM CARD ────────────────────────────────────────────
function CatalogItemCard({ item, categories, setItems, startEdit, handlePhoto, onDelete }) {
  const cat = categories.find(c => c.id === item.catId);
  const margin = item.costPerUnit && item.price ? (((item.price - item.costPerUnit) / item.price) * 100).toFixed(0) : null;
  return (
    <div style={{ ...S.card, padding: 0, overflow: "hidden" }}>
      <div style={{ height: 120, background: T.surface, position: "relative", cursor: "pointer" }}
        onClick={() => { const inp = document.createElement("input"); inp.type = "file"; inp.accept = "image/*"; inp.onchange = e => handlePhoto(e, item.id); inp.click(); }}>
        {item.photo
          ? <img src={item.photo} alt={item.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
          : <div style={{ height: "100%", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", color: T.textDim, gap: 3 }}>
              <div style={{ fontSize: 24 }}>📷</div>
              <div style={{ fontSize: 9 }}>Click to add photo</div>
            </div>
        }
        <div style={{ position: "absolute", bottom: 4, right: 4, background: "rgba(0,0,0,0.5)", color: "#fff", fontSize: 8, padding: "2px 5px", borderRadius: 3 }}>📷</div>
      </div>
      <div style={{ padding: 9 }}>
        <div style={{ fontSize: 11, fontWeight: 700, marginBottom: 1 }}>{item.name}</div>
        <div style={{ fontSize: 10, color: T.textMuted, marginBottom: 3 }}>{cat?.name}</div>
        {item.description && <div style={{ fontSize: 9, color: T.textDim, marginBottom: 4, lineHeight: 1.4 }}>{item.description}</div>}
        {item.notes && <div style={{ fontSize: 9, color: T.accent, marginBottom: 4, fontStyle: "italic" }}>📝 {item.notes}</div>}
        <div style={{ display: "flex", alignItems: "center", gap: 4, marginBottom: 3 }}>
          <input type="number" value={item.price}
            onChange={e => setItems(prev => prev.map(it => it.id === item.id ? { ...it, price: Number(e.target.value) } : it))}
            style={{ ...S.input, width: 90, padding: "3px 5px", fontSize: 12, fontWeight: 800, color: T.accent }} />
          <span style={{ fontSize: 9, color: T.textMuted }}>USD / {item.unitType}</span>
        </div>
        {item.costPerUnit > 0 && (
          <div style={{ fontSize: 9, color: T.textMuted, marginBottom: 4 }}>
            Cost: {fmt(item.costPerUnit)} {margin && <span style={{ color: T.success }}>· Margin: {margin}%</span>}
          </div>
        )}
        {/* Move to category */}
        <div style={{ marginBottom: 6 }}>
          <select
            style={{ ...S.select, fontSize: 10, padding: "2px 4px", color: T.textMuted }}
            value={item.catId}
            onChange={e => {
              const newCatId = Number(e.target.value);
              if (newCatId === item.catId) return;
              const newCat = categories.find(c => c.id === newCatId);
              // Preserve photo explicitly when moving category
              setItems(prev => prev.map(it => it.id === item.id ? { ...it, catId: newCatId, photo: it.photo } : it));
              if (newCat) {
                // Brief visual confirmation
                setTimeout(() => alert(`✅ "${item.name}" moved to ${newCat.name}`), 50);
              }
            }}
            onClick={e => e.stopPropagation()}
          >
            {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
        </div>
        <div style={{ display: "flex", gap: 3, alignItems: "center", flexWrap: "wrap", marginTop: 4 }}>
          {(Array.isArray(item.tags) ? item.tags : []).map(t => <span key={t} style={S.tag}>{t}</span>)}
          <div style={{ marginLeft: "auto", display: "flex", gap: 4 }}>
            <button style={{ ...S.btn("ghost"), fontSize: 9, padding: "1px 6px" }} onClick={() => startEdit(item)}>Edit</button>
            {onDelete && <button style={{ ...S.btn("ghost"), fontSize: 9, padding: "1px 6px", color: T.danger, borderColor: T.danger + "40" }} onClick={onDelete}>✕</button>}
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── PROPOSALS (with inventory linking) ───────────────────────────
function ProposalsPage({
  proposals,
  setProposals,
  events,
  setEvents,
  catalogItems,
  setCatalogItems,
  catalogCategories,
  inventory,
  logo,
  biz,
  customers,
  invoices,
  setInvoices,
  proposalPrefillLines,
  clearProposalPrefill,
}) {
  const [sel, setSel] = useState(null);
  const [building, setBuilding] = useState(false);
  const [editingPropIdx, setEditingPropIdx] = useState(null); // index of proposal being edited
  const [draft, setDraft] = useState({
    client: "",
    clientPhone: "",
    eventType: "",
    plannedDate: "",
    guests: "",
    location: "",
    discount: 0,
    notes: "",
    lines: [],
    inventoryLinks: [],
    eventId: null,
  });
  const [pickCat, setPickCat] = useState(null);
  const [doc, setDoc] = useState(null);
  const [showInvLink, setShowInvLink] = useState(null); // proposal index
  const [showTemplates, setShowTemplates] = useState(false);
  const [addingCatalogItem, setAddingCatalogItem] = useState(false);
  const [newCatItem, setNewCatItem] = useState({ name:"", catId: catalogCategories[0]?.id || 1, unitType:"Tray", price:"", costPerUnit:"", description:"", photo:null });
  const newCatItemPhotoRef = useRef();
  const openDoc = (title, html) =>
    setDoc({ title, html, onPrint: () => printDoc(title, html) });

  // Auto-open builder pre-seeded when arriving from Catalog → "Create Proposal from Category"
  useEffect(() => {
    if (proposalPrefillLines && proposalPrefillLines.length > 0) {
      setDraft(d => ({ ...d, lines: proposalPrefillLines }));
      setBuilding(true);
      setShowTemplates(false);
      if (clearProposalPrefill) clearProposalPrefill();
    }
  }, [proposalPrefillLines]);

  const BLANK_DRAFT = {
    client: "", clientPhone: "", eventType: "", plannedDate: "",
    guests: "", location: "", discount: 0, notes: "", lines: [],
    inventoryLinks: [], eventId: null, paymentTerms: "",
  };

  const duplicateProposal = (i) => {
    const src = proposals[i];
    const newNum = proposals.length + 1;
    const copy = {
      ...src,
      id: Date.now(),
      num: `PROP-${THIS_YEAR}-${String(newNum).padStart(4, "0")}`,
      status: "Draft",
      // Clear client-specific fields — keep line items, discount, notes
      client: "",
      clientPhone: "",
      plannedDate: "",
      eventId: null,
      duplicatedFrom: src.num,
    };
    setProposals(prev => [copy, ...prev]);
  };

  const loadTemplate = (propId) => {
    const src = proposals.find(p => p.id === Number(propId));
    if (!src) return;
    setDraft(d => ({
      ...d,
      lines: src.lines.map(l => ({ ...l })),
      discount: src.discount,
      notes: src.notes,
      inventoryLinks: src.inventoryLinks || [],
      eventType: d.eventType || src.eventType,
    }));
    setShowTemplates(false);
  };

  const toggleTemplate = (i) => {
    const u = [...proposals];
    u[i] = { ...u[i], isTemplate: !u[i].isTemplate };
    setProposals(u);
  };

  const templates = proposals.filter(p => p.isTemplate);

  const addLine = (item) =>
    setDraft((d) => ({
      ...d,
      lines: [
        ...d.lines,
        {
          itemId: item.id,
          name: item.name,
          qty: item.unitType === "Per head" ? d.guests : 1,
          price: item.price,
          unitType: item.unitType,
        },
      ],
    }));
  const saveDraft = () => {
    if (editingPropIdx !== null) {
      // Editing an existing proposal — preserve id, num, status, eventId
      const existing = proposals[editingPropIdx];
      const updated = { ...existing, ...draft, id: existing.id, num: existing.num, eventId: existing.eventId };
      const u = [...proposals];
      u[editingPropIdx] = updated;
      setProposals(u);
      setEditingPropIdx(null);
    } else {
      const newNum = proposals.length + 1;
      const p = {
        ...draft,
        id: Date.now(),
        num: `PROP-${THIS_YEAR}-${String(newNum).padStart(4, "0")}`,
        status: "Draft",
      };
      setProposals((prev) => [...prev, p]);
    }
    setBuilding(false);
    setDraft({ ...BLANK_DRAFT });
  };
  const updateLine = (pi, li, field, value) => {
    const u = [...proposals];
    u[pi] = {
      ...u[pi],
      lines: u[pi].lines.map((l, i) =>
        i === li ? { ...l, [field]: Number(value) } : l
      ),
    };
    setProposals(u);
  };
  const stColor = {
    Draft: T.textMuted,
    Sent: T.info,
    Negotiation: T.warning,
    Approved: T.success,
    Declined: T.danger,
    "Converted to Event": T.catering,
  };

  const toggleInventoryLink = (propIdx, invId) => {
    const u = [...proposals];
    const links = u[propIdx].inventoryLinks || [];
    const has = links.includes(invId);
    u[propIdx] = {
      ...u[propIdx],
      inventoryLinks: has
        ? links.filter((id) => id !== invId)
        : [...links, invId],
    };
    setProposals(u);
  };
  const toggleDraftInvLink = (invId) => {
    const has = (draft.inventoryLinks || []).includes(invId);
    setDraft({
      ...draft,
      inventoryLinks: has
        ? draft.inventoryLinks.filter((id) => id !== invId)
        : [...(draft.inventoryLinks || []), invId],
    });
  };

  // Link/unlink a proposal to an existing event
  const linkProposalToEvent = (propIdx, eventId) => {
    const u = [...proposals];
    u[propIdx] = { ...u[propIdx], eventId: eventId || null };
    setProposals(u);
  };

  // Convert an approved proposal into a new catering event (or link to existing)
  const convertToEvent = (propIdx) => {
    const p = proposals[propIdx];
    const total = propTotal(p.lines, p.discount);
    const guests = Number(p.guests) || 0;
    const pricePerHead = guests > 0 ? Math.round(total / guests) : 0;
    const eventId = Date.now();
    const newEvent = {
      id: eventId,
      name: `${p.eventType || "Event"} – ${p.client}`,
      clientName: p.client,
      clientPhone: p.clientPhone || "",
      eventDate: p.plannedDate || "",
      location: p.location || "",
      eventType: p.eventType || "Other",
      serviceStyle: "Buffet",
      guests,
      pricePerHead,
      addOns: 0,
      discount: Number(p.discount) || 0,
      phase: "Confirmed",
      notes: p.notes || `Converted from proposal ${p.num}`,
      revenue: total,
      media: [],
      costs: { inventory: 0, labor: 0, transport: 0, overhead: 0 },
      costLines: [],
    };
    setEvents((prev) => [...prev, newEvent]);

    // Auto-generate invoice for the new event
    const thisYear = new Date().getFullYear();
    const inv = {
      id: eventId + 1,
      num: `INV-${thisYear}-${String(eventId).slice(-4)}`,
      client: p.client,
      clientPhone: p.clientPhone || "",
      issued: p.plannedDate || new Date().toISOString().slice(0, 10),
      due: p.plannedDate || new Date().toISOString().slice(0, 10),
      total,
      paid: 0,
      status: "Unpaid",
      eventId,
      notes: `Auto-generated from proposal ${p.num}`,
    };
    setInvoices((prev) => [...prev, inv]);

    const u = [...proposals];
    u[propIdx] = { ...p, status: "Converted to Event", eventId };
    setProposals(u);
  };

  return (
    <div>
      <DocModal doc={doc} onClose={() => setDoc(null)} />
      <div style={{ ...S.row, marginBottom: 14 }}>
        <div>
          <div style={S.pageTitle}>📋 Proposals</div>
          <div style={S.subtitle}>
            Build and send proposals to clients
            {templates.length > 0 && <span style={{ ...S.badge(T.accent), marginLeft: 6 }}>⭐ {templates.length} template{templates.length > 1 ? "s" : ""}</span>}
          </div>
        </div>
        <button style={S.btn("primary")} onClick={() => { setBuilding(!building); setShowTemplates(false); if (building) { setEditingPropIdx(null); setDraft({ ...BLANK_DRAFT }); } }}>
          {building ? "✕ Cancel" : "+ New Proposal"}
        </button>
      </div>

      {building && (
        <div style={{ ...S.card, marginBottom: 14, borderColor: editingPropIdx !== null ? T.warning : T.accent }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
            <div style={S.sectionTitle}>{editingPropIdx !== null ? `✏️ Edit Proposal — ${proposals[editingPropIdx]?.num}` : "Build Proposal"}</div>
            {proposals.length > 0 && (
              <button style={{ ...S.btn("ghost"), fontSize: 11, padding: "4px 10px" }} onClick={() => setShowTemplates(!showTemplates)}>
                {showTemplates ? "✕ Close" : "📋 Load from existing…"}
              </button>
            )}
          </div>

          {/* Template / existing proposal picker */}
          {showTemplates && (
            <div style={{ background: T.accentSoft, borderRadius: 8, padding: "10px 12px", marginBottom: 14 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: T.accent, marginBottom: 8 }}>
                ⚡ Load line items from an existing proposal — client details stay blank for you to fill in
              </div>
              {/* Starred templates first */}
              {templates.length > 0 && (
                <>
                  <div style={{ fontSize: 10, color: T.textMuted, fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 5 }}>⭐ Saved Templates</div>
                  <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 10 }}>
                    {templates.map(t => (
                      <button key={t.id} style={{ ...S.btn("primary"), fontSize: 11, padding: "5px 12px" }} onClick={() => loadTemplate(t.id)}>
                        {t.num} · {t.eventType || "Template"} · {t.lines.length} items · {fmt(propTotal(t.lines, t.discount))}
                      </button>
                    ))}
                  </div>
                </>
              )}
              <div style={{ fontSize: 10, color: T.textMuted, fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 5 }}>All Proposals</div>
              <select style={{ ...S.select, width: "100%" }} defaultValue="" onChange={e => { if (e.target.value) loadTemplate(e.target.value); }}>
                <option value="">— Pick a proposal to copy its line items —</option>
                {proposals.map(pr => (
                  <option key={pr.id} value={pr.id}>
                    {pr.isTemplate ? "⭐ " : ""}{pr.num} · {pr.client || "No client"} · {pr.eventType || "—"} · {pr.lines.length} items · {fmt(propTotal(pr.lines, pr.discount))} · {pr.status}
                  </option>
                ))}
              </select>
              {draft.lines.length > 0 && (
                <div style={{ marginTop: 8, fontSize: 11, color: T.accent, fontWeight: 600 }}>
                  ✓ {draft.lines.length} line items loaded — fill in client details below
                </div>
              )}
            </div>
          )}
          <div style={S.grid(3)}>
            <div>
              <label style={S.label}>Client Name</label>
              <input
                style={S.input}
                value={draft.client}
                onChange={(e) => setDraft({ ...draft, client: e.target.value })}
              />
            </div>
            <div>
              <label style={S.label}>Client Phone</label>
              <input
                style={S.input}
                value={draft.clientPhone}
                onChange={(e) =>
                  setDraft({ ...draft, clientPhone: e.target.value })
                }
              />
            </div>
            <div>
              <label style={S.label}>Event Type</label>
              <input
                style={S.input}
                value={draft.eventType}
                onChange={(e) =>
                  setDraft({ ...draft, eventType: e.target.value })
                }
              />
            </div>
            <div>
              <label style={S.label}>Planned Date</label>
              <input
                type="date"
                style={S.input}
                value={draft.plannedDate}
                onChange={(e) =>
                  setDraft({ ...draft, plannedDate: e.target.value })
                }
              />
            </div>
            <div>
              <label style={S.label}>Guest Count</label>
              <input
                type="number"
                style={S.input}
                value={draft.guests}
                onChange={(e) =>
                  setDraft({ ...draft, guests: Number(e.target.value) })
                }
              />
            </div>
            <div>
              <label style={S.label}>Location</label>
              <input
                style={S.input}
                value={draft.location}
                onChange={(e) =>
                  setDraft({ ...draft, location: e.target.value })
                }
              />
            </div>
            <div>
              <label style={S.label}>Discount (USD)</label>
              <input
                type="number"
                style={S.input}
                value={draft.discount}
                onChange={(e) =>
                  setDraft({ ...draft, discount: Number(e.target.value) })
                }
              />
            </div>
            <div style={{ gridColumn: "span 2" }}>
              <label style={S.label}>Notes</label>
              <input
                style={S.input}
                value={draft.notes}
                onChange={(e) => setDraft({ ...draft, notes: e.target.value })}
              />
            </div>
            <div style={{ gridColumn: "span 2" }}>
              <label style={S.label}>Payment Terms <span style={{ color: T.textDim, fontWeight: 400 }}>(overrides business default on this proposal)</span></label>
              <textarea
                style={{ ...S.input, minHeight: 60, resize: "vertical" }}
                placeholder={biz.paymentTerms || "e.g. 50% deposit required. Balance due before event date."}
                value={draft.paymentTerms || ""}
                onChange={(e) => setDraft({ ...draft, paymentTerms: e.target.value })}
              />
            </div>
            <div style={{ gridColumn: "span 2" }}>
              <label style={S.label}>🎉 Link to Catering Event <span style={{ color: T.textDim, fontWeight: 400 }}>(optional)</span></label>
              <select
                style={S.select}
                value={draft.eventId || ""}
                onChange={(e) => setDraft({ ...draft, eventId: e.target.value ? Number(e.target.value) : null })}
              >
                <option value="">— No event linked (create later) —</option>
                {events.map((ev) => (
                  <option key={ev.id} value={ev.id}>
                    {ev.name} · {ev.eventDate || "Date TBD"} · {ev.phase}
                  </option>
                ))}
              </select>
            </div>
          </div>
          <Divider />
          {/* ── Catalog item picker header ── */}
          <div style={{ ...S.row, marginBottom: 7, alignItems: "center" }}>
            <div style={{ fontSize: 11, fontWeight: 600 }}>Select items from catalog:</div>
            <button
              type="button"
              style={{ ...S.btn("ghost"), fontSize: 10, padding: "2px 9px", color: T.success, border: `1px solid ${T.success}50` }}
              onClick={() => { setAddingCatalogItem(!addingCatalogItem); setNewCatItem({ name:"", catId: catalogCategories[0]?.id || 1, unitType:"Tray", price:"", costPerUnit:"", description:"", photo:null }); }}
            >
              {addingCatalogItem ? "✕ Cancel" : "+ New Item"}
            </button>
          </div>

          {/* ── Inline add-catalog-item form ── */}
          {addingCatalogItem && (
            <div style={{ background: `${T.success}0D`, border: `1px solid ${T.success}30`, borderRadius: 9, padding: "12px 14px", marginBottom: 12 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: T.success, marginBottom: 10 }}>✚ Add New Catalog Item</div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 8 }}>
                <div style={{ gridColumn: "span 2" }}>
                  <label style={S.label}>Item Name</label>
                  <input style={S.input} placeholder="e.g. Jollof Rice and Fried Rice" value={newCatItem.name}
                    onChange={e => setNewCatItem({ ...newCatItem, name: e.target.value })} />
                </div>
                <div>
                  <label style={S.label}>Category</label>
                  <select style={S.select} value={newCatItem.catId}
                    onChange={e => setNewCatItem({ ...newCatItem, catId: Number(e.target.value) })}>
                    {catalogCategories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                </div>
                <div>
                  <label style={S.label}>Unit Type</label>
                  <select style={S.select} value={newCatItem.unitType}
                    onChange={e => setNewCatItem({ ...newCatItem, unitType: e.target.value })}>
                    {["Tray","Per head","Per gallon","Per box","Per pack","Per hour","Per table","Flat","Per unit"].map(u => <option key={u}>{u}</option>)}
                  </select>
                </div>
                <div>
                  <label style={S.label}>Price (USD)</label>
                  <input type="number" style={S.input} placeholder="0.00" value={newCatItem.price}
                    onChange={e => setNewCatItem({ ...newCatItem, price: e.target.value })} />
                </div>
                <div>
                  <label style={S.label}>Cost per Unit (USD)</label>
                  <input type="number" style={S.input} placeholder="0.00" value={newCatItem.costPerUnit}
                    onChange={e => setNewCatItem({ ...newCatItem, costPerUnit: e.target.value })} />
                </div>
                <div style={{ gridColumn: "span 2" }}>
                  <label style={S.label}>Description <span style={{ color: T.textDim, fontWeight: 400 }}>(optional — appears on proposals)</span></label>
                  <input style={S.input} placeholder="e.g. Full tray $140 · Half tray $70. Our signature dish." value={newCatItem.description}
                    onChange={e => setNewCatItem({ ...newCatItem, description: e.target.value })} />
                </div>
              </div>

              {/* Photo upload */}
              <div style={{ marginBottom: 10 }}>
                <label style={S.label}>Photo <span style={{ color: T.textDim, fontWeight: 400 }}>(appears on proposals automatically)</span></label>
                <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                  {newCatItem.photo ? (
                    <img src={newCatItem.photo} alt="" style={{ width: 64, height: 64, objectFit: "cover", borderRadius: 7, border: `1px solid ${T.border}` }} />
                  ) : (
                    <div style={{ width: 64, height: 64, borderRadius: 7, background: T.surface, border: `1px dashed ${T.border}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22, color: T.textDim }}>📷</div>
                  )}
                  <div style={{ display: "flex", flexDirection: "column", gap: 5 }}>
                    <button type="button" style={{ ...S.btn("ghost"), fontSize: 11, padding: "3px 10px" }}
                      onClick={() => newCatItemPhotoRef.current.click()}>
                      {newCatItem.photo ? "Change Photo" : "Upload Photo"}
                    </button>
                    {newCatItem.photo && (
                      <button type="button" style={{ background: "none", border: "none", color: T.danger, cursor: "pointer", fontSize: 11 }}
                        onClick={() => setNewCatItem({ ...newCatItem, photo: null })}>✕ Remove</button>
                    )}
                  </div>
                  <input ref={newCatItemPhotoRef} type="file" accept="image/*" style={{ display: "none" }}
                    onChange={e => {
                      const f = e.target.files[0]; if (!f) return;
                      const r = new FileReader();
                      r.onload = ev => setNewCatItem(prev => ({ ...prev, photo: ev.target.result }));
                      r.readAsDataURL(f);
                    }} />
                </div>
              </div>

              {/* Save button */}
              <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                <button
                  type="button"
                  style={{ ...S.btn("primary"), fontSize: 12, padding: "5px 14px", opacity: newCatItem.name.trim() && newCatItem.price ? 1 : 0.45 }}
                  onClick={() => {
                    if (!newCatItem.name.trim() || !newCatItem.price) return;
                    const saved = {
                      id: Date.now(),
                      name: newCatItem.name.trim(),
                      catId: newCatItem.catId,
                      unitType: newCatItem.unitType,
                      price: Number(newCatItem.price),
                      costPerUnit: Number(newCatItem.costPerUnit) || 0,
                      description: newCatItem.description.trim(),
                      photo: newCatItem.photo || null,
                      tags: [],
                    };
                    setCatalogItems(prev => [...prev, saved]);
                    // Auto-add to current proposal draft immediately
                    setDraft(prev => ({ ...prev, lines: [...prev.lines, { name: saved.name, qty: 1, price: saved.price, unitType: saved.unitType }] }));
                    setPickCat(saved.catId);
                    setAddingCatalogItem(false);
                    setNewCatItem({ name:"", catId: catalogCategories[0]?.id || 1, unitType:"Tray", price:"", costPerUnit:"", description:"", photo:null });
                  }}
                >
                  ✓ Save & Add to Proposal
                </button>
                <span style={{ fontSize: 11, color: T.textDim }}>Item is saved to your catalog and added to this proposal.</span>
              </div>
            </div>
          )}

          {/* ── Category filter buttons ── */}
          <div
            style={{
              display: "flex",
              gap: 3,
              flexWrap: "wrap",
              marginBottom: 9,
            }}
          >
            {catalogCategories.map((c) => (
              <button
                key={c.id}
                style={S.navBtn(pickCat === c.id)}
                onClick={() => setPickCat(pickCat === c.id ? null : c.id)}
              >
                {c.name}
              </button>
            ))}
          </div>
          <div style={S.grid(4)}>
            {catalogItems
              .filter((i) => !pickCat || i.catId === pickCat)
              .map((item) => (
                <div
                  key={item.id}
                  style={{
                    ...S.card,
                    padding: 0,
                    overflow: "hidden",
                    cursor: "pointer",
                  }}
                  onClick={() => addLine(item)}
                >
                  {item.photo ? (
                    <img
                      src={item.photo}
                      alt=""
                      style={{ width: "100%", height: 60, objectFit: "cover" }}
                    />
                  ) : (
                    <div
                      style={{
                        height: 40,
                        background: T.surface,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        color: T.textDim,
                        fontSize: 16,
                      }}
                    >
