                  </button>
                  <button
                    style={{ ...S.btn("ghost"), fontSize: 11, padding: "4px 9px",
                      borderColor: p.isTemplate ? T.accent : T.border,
                      color: p.isTemplate ? T.accent : T.textMuted,
                      background: p.isTemplate ? T.accentSoft : "transparent",
                    }}
                    onClick={(e) => { e.stopPropagation(); toggleTemplate(i); }}
                    title={p.isTemplate ? "Remove from templates" : "Save as reusable template"}
                  >
                    {p.isTemplate ? "⭐ Template" : "☆ Save as Template"}
                  </button>
                  <button
                    style={{ ...S.btn("ghost"), fontSize: 11, padding: "4px 9px", color: T.danger, borderColor: T.danger + "40", marginLeft: "auto" }}
                    onClick={(e) => { e.stopPropagation(); if (window.confirm(`Delete ${p.num}?`)) setProposals(prev => prev.filter((_, j) => j !== i)); }}
                  >
                    🗑 Delete
                  </button>
                </div>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

// ─── BATCHES TAB ──────────────────────────────────────────────────
function BatchesTab({ batches, setBatches, meals, setMeals, inventory, setInventory, getMealTotalCost, sales }) {
  const isMobile = useIsMobile();
  const TODAY = new Date().toISOString().slice(0, 10);

  const EMPTY_BATCH = {
    date: TODAY,
    mealId: "",
    mealName: "",
    portions: "",
    totalCost: "",
    notes: "",
    deductInventory: true,
  };
  const [adding, setAdding] = useState(false);
  const [editBatchId, setEditBatchId] = useState(null);
  const [nb, setNb] = useState(EMPTY_BATCH);
  const [filterDate, setFilterDate] = useState("");
  const [confirm, setConfirm] = useState(null); // batch id to delete

  const selectedMeal = meals.find((m) => m.id === Number(nb.mealId));
  const suggestedCost = selectedMeal ? getMealTotalCost(selectedMeal) * Number(nb.portions || 0) : 0;

  const saveBatch = () => {
    if (!nb.mealName || !nb.portions) return;
    const portions = Number(nb.portions);
    const totalCost = nb.totalCost !== "" ? Number(nb.totalCost) : suggestedCost;
    const costPerPortion = portions > 0 ? totalCost / portions : 0;

    const batch = {
      id: editBatchId || Date.now(),
      date: nb.date,
      mealId: nb.mealId ? Number(nb.mealId) : null,
      mealName: nb.mealName,
      portions,
      totalCost,
      costPerPortion,
      notes: nb.notes,
      deductInventory: nb.deductInventory,
    };

    if (editBatchId) {
      // Editing: adjust meal availablePortions by the difference
      const oldBatch = batches.find((b) => b.id === editBatchId);
      const portionDiff = portions - (oldBatch?.portions || 0);
      if (selectedMeal && portionDiff !== 0) {
        setMeals((prev) =>
          prev.map((m) =>
            m.id === selectedMeal.id
              ? { ...m, availablePortions: Math.max(0, (Number(m.availablePortions) || 0) + portionDiff) }
              : m
          )
        );
      }
      setBatches((prev) => prev.map((b) => b.id === editBatchId ? batch : b));
    } else {
      // New batch: deduct inventory and add portions
      if (nb.deductInventory && selectedMeal?.ingredientLinks?.length) {
        setInventory((prev) =>
          prev.map((item) => {
            const link = selectedMeal.ingredientLinks.find((l) => l.inventoryId === item.id);
            if (!link) return item;
            return { ...item, stock: Math.max(0, item.stock - link.qty * portions) };
          })
        );
      }
      if (selectedMeal) {
        setMeals((prev) =>
          prev.map((m) =>
            m.id === selectedMeal.id
              ? { ...m, availablePortions: (Number(m.availablePortions) || 0) + portions }
              : m
          )
        );
      }
      setBatches((prev) => [batch, ...prev]);
    }

    setAdding(false);
    setEditBatchId(null);
    setNb(EMPTY_BATCH);
  };

  const deleteBatch = (id) => {
    // Restore portions to the linked meal when deleting a batch
    const b = batches.find((bt) => bt.id === id);
    if (b?.mealId) {
      setMeals((prev) =>
        prev.map((m) =>
          m.id === b.mealId
            ? { ...m, availablePortions: Math.max(0, (Number(m.availablePortions) || 0) - b.portions) }
            : m
        )
      );
    }
    setBatches((prev) => prev.filter((bt) => bt.id !== id));
    setConfirm(null);
  };

  const startEditBatch = (b) => {
    setNb({
      date: b.date,
      mealId: b.mealId ? String(b.mealId) : "",
      mealName: b.mealName,
      portions: String(b.portions),
      totalCost: String(b.totalCost),
      notes: b.notes || "",
      deductInventory: false, // don't re-deduct on edit
    });
    setEditBatchId(b.id);
    setAdding(true);
  };

  // Compute remaining portions for a batch: batch.portions minus all sales of that meal on/after batch date
  const batchRemaining = (b) => {
    if (!b.mealId) return null; // manual batches without linked meal — unknown
    const sold = (sales || [])
      .filter((s) => s.mealId === b.mealId && s.date >= b.date)
      .reduce((sum, s) => sum + Number(s.plates || 0), 0);
    return Math.max(0, b.portions - sold);
  };

  const filtered = filterDate
    ? batches.filter((b) => b.date === filterDate)
    : batches;

  const totalPortions = filtered.reduce((s, b) => s + b.portions, 0);
  const totalCost = filtered.reduce((s, b) => s + b.totalCost, 0);
  const avgCostPerPortion = totalPortions > 0 ? totalCost / totalPortions : 0;
  const todayBatches = batches.filter((b) => b.date === TODAY);
  const todayPortions = todayBatches.reduce((s, b) => s + b.portions, 0);

  return (
    <div>
      {/* KPI row */}
      <div style={S.grid(4)}>
        <KpiCard label="Today's Portions" value={todayPortions} icon="🍽️" color={T.accent} />
        <KpiCard label="Today's Batches" value={todayBatches.length} icon="🍳" color={T.restaurant} />
        <KpiCard label="Total Cost (filtered)" value={fmt(totalCost)} icon="💰" color={T.warning} />
        <KpiCard label="Avg Cost / Portion" value={fmt(avgCostPerPortion)} icon="📊" />
      </div>

      {/* Header row */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", margin: "16px 0 10px" }}>
        <div style={{ display: "flex", gap: 8, alignItems: "center", flexWrap: "wrap" }}>
          <div style={{ fontSize: 13, fontWeight: 700 }}>🍳 Production Batches</div>
          <input
            type="date"
            value={filterDate}
            onChange={(e) => setFilterDate(e.target.value)}
            style={{ ...S.input, width: 140, marginBottom: 0, fontSize: 11 }}
          />
          {filterDate && (
            <button style={{ ...S.btn("ghost"), fontSize: 11, padding: "3px 8px" }} onClick={() => setFilterDate("")}>
              Clear filter
            </button>
          )}
        </div>
        <button style={{ ...S.btn("primary"), fontSize: 12, padding: "6px 14px" }} onClick={() => { setAdding(true); setNb(EMPTY_BATCH); }}>
          + Log Batch
        </button>
      </div>

      {/* Add batch form */}
      {adding && (
        <div style={{ background: T.card, border: `1px solid ${T.accent}40`, borderRadius: 10, padding: 16, marginBottom: 14 }}>
          <div style={{ fontWeight: 700, fontSize: 13, marginBottom: 12, color: T.accent }}>{editBatchId ? "✏️ Edit Batch" : "🍳 Log Production Batch"}</div>
          <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr", gap: 10 }}>
            <div>
              <label style={S.label}>Date</label>
              <input type="date" style={S.input} value={nb.date} onChange={(e) => setNb((n) => ({ ...n, date: e.target.value }))} />
            </div>
            <div>
              <label style={S.label}>Meal / Dish</label>
              <select
                style={S.select}
                value={nb.mealId}
                onChange={(e) => {
                  const meal = meals.find((m) => m.id === Number(e.target.value));
                  setNb((n) => ({ ...n, mealId: e.target.value, mealName: meal ? meal.name : "" }));
                }}
              >
                <option value="">— Select a meal or type below —</option>
                {meals.map((m) => (
                  <option key={m.id} value={m.id}>{m.name}</option>
                ))}
              </select>
              {!nb.mealId && (
                <input
                  style={{ ...S.input, marginTop: 6 }}
                  placeholder="Or type meal name manually"
                  value={nb.mealName}
                  onChange={(e) => setNb((n) => ({ ...n, mealName: e.target.value }))}
                />
              )}
            </div>
            <div>
              <label style={S.label}>Portions Produced</label>
              <input
                type="number"
                style={S.input}
                placeholder="e.g. 25"
                value={nb.portions}
                onChange={(e) => setNb((n) => ({ ...n, portions: e.target.value }))}
              />
            </div>
            <div>
              <label style={S.label}>
                Total Production Cost (USD)
                {suggestedCost > 0 && (
                  <span
                    style={{ color: T.accent, marginLeft: 6, cursor: "pointer", fontWeight: 400 }}
                    onClick={() => setNb((n) => ({ ...n, totalCost: String(Math.round(suggestedCost)) }))}
                  >
                    ← Use suggested: {fmt(suggestedCost)}
                  </span>
                )}
              </label>
              <input
                type="number"
                style={S.input}
                placeholder={suggestedCost > 0 ? `Suggested: ${Math.round(suggestedCost)}` : "e.g. 25.00"}
                value={nb.totalCost}
                onChange={(e) => setNb((n) => ({ ...n, totalCost: e.target.value }))}
              />
              {nb.portions && nb.totalCost && (
                <div style={{ fontSize: 10, color: T.accent, marginTop: 3 }}>
                  → {fmt(Number(nb.totalCost) / Number(nb.portions))} per portion
                </div>
              )}
              {nb.portions && !nb.totalCost && suggestedCost > 0 && (
                <div style={{ fontSize: 10, color: T.textMuted, marginTop: 3 }}>
                  → Suggested {fmt(suggestedCost / Number(nb.portions))} per portion
                </div>
              )}
            </div>
            <div style={{ gridColumn: isMobile ? "1" : "1 / -1" }}>
              <label style={S.label}>Notes (optional)</label>
              <input style={S.input} placeholder="e.g. Used extra seasoning, packed in 12oz containers" value={nb.notes} onChange={(e) => setNb((n) => ({ ...n, notes: e.target.value }))} />
            </div>
          </div>

          {/* Inventory deduction toggle — hidden in edit mode */}
          {!editBatchId && selectedMeal?.ingredientLinks?.length > 0 && (
            <div style={{ marginTop: 10, padding: "8px 12px", background: T.surface, borderRadius: 8, display: "flex", alignItems: "center", gap: 10 }}>
              <input
                type="checkbox"
                id="deductInv"
                checked={nb.deductInventory}
                onChange={(e) => setNb((n) => ({ ...n, deductInventory: e.target.checked }))}
                style={{ accentColor: T.accent }}
              />
              <label htmlFor="deductInv" style={{ fontSize: 11, color: T.textMuted, cursor: "pointer" }}>
                Auto-deduct ingredients from inventory ({selectedMeal.ingredientLinks.length} linked ingredient{selectedMeal.ingredientLinks.length > 1 ? "s" : ""})
              </label>
            </div>
          )}

          {editBatchId && (
            <div style={{ marginTop: 10, padding: "7px 11px", background: T.surface, borderRadius: 7, fontSize: 11, color: T.textMuted }}>
              ℹ️ Editing a batch updates the portion count. Inventory will not be re-deducted. To fix inventory, edit it directly in the Inventory tab.
            </div>
          )}
          <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
            <button
              style={{ ...S.btn("primary"), fontSize: 12, opacity: (!nb.mealName || !nb.portions) ? 0.5 : 1 }}
              disabled={!nb.mealName || !nb.portions}
              onClick={saveBatch}
            >
              {editBatchId ? "✓ Update Batch" : "✓ Save Batch"}
            </button>
            <button style={{ ...S.btn("ghost"), fontSize: 12 }} onClick={() => { setAdding(false); setEditBatchId(null); setNb(EMPTY_BATCH); }}>
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Production table */}
      {filtered.length === 0 ? (
        <div style={{ color: T.textMuted, padding: 36, textAlign: "center", background: T.card, borderRadius: 10, border: `1px solid ${T.border}` }}>
          <div style={{ fontSize: 32, marginBottom: 8 }}>🍳</div>
          <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 4 }}>No batches recorded yet</div>
          <div style={{ fontSize: 11, lineHeight: 1.7 }}>
            Click <strong>+ Log Batch</strong> to record a production run.<br />
            e.g. Spicy Chicken Box · 25 portions · Cost: 47,500 USD · 1,900 USD/portion
          </div>
        </div>
      ) : (
        <div className="tbl-wrap">
          <table style={S.table}>
            <thead>
              <tr>
                {["Date", "Meal / Dish", "Portions", "Remaining", "Total Cost", "Cost/Portion", "Inv. Deducted", "Notes", ""].map((h) => (
                  <th key={h} style={S.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map((b) => (
                <tr key={b.id}>
                  <td style={{ ...S.td, whiteSpace: "nowrap", color: T.textMuted }}>{b.date}</td>
                  <td style={{ ...S.td, fontWeight: 700 }}>{b.mealName}</td>
                  <td style={{ ...S.td, color: T.accent, fontWeight: 700 }}>{b.portions}</td>
                  <td style={S.td}>
                    {(() => {
                      const rem = batchRemaining(b);
                      if (rem === null) return <span style={{ color: T.textDim }}>—</span>;
                      if (rem === 0) return <span style={{ color: T.danger, fontWeight: 700 }}>0 sold out</span>;
                      if (rem <= 5) return <span style={{ color: T.warning, fontWeight: 700 }}>{rem} low</span>;
                      return <span style={{ color: T.success, fontWeight: 700 }}>{rem}</span>;
                    })()}
                  </td>
                  <td style={{ ...S.td }}>{fmt(b.totalCost)}</td>
                  <td style={{ ...S.td, color: T.success }}>{fmt(b.costPerPortion)}</td>
                  <td style={{ ...S.td, textAlign: "center" }}>
                    {b.deductInventory ? (
                      <span style={{ color: T.success, fontSize: 12 }}>✓</span>
                    ) : (
                      <span style={{ color: T.textDim, fontSize: 12 }}>—</span>
                    )}
                  </td>
                  <td style={{ ...S.td, color: T.textMuted, fontSize: 11 }}>{b.notes || "—"}</td>
                  <td style={S.td}>
                    <div style={{ display: "flex", gap: 4 }}>
                      {confirm === b.id ? (
                        <>
                          <button style={{ ...S.btn("ghost"), fontSize: 10, padding: "2px 7px", color: T.danger, borderColor: T.danger + "50" }} onClick={() => deleteBatch(b.id)}>Delete</button>
                          <button style={{ ...S.btn("ghost"), fontSize: 10, padding: "2px 7px" }} onClick={() => setConfirm(null)}>Cancel</button>
                        </>
                      ) : (
                        <>
                          <button style={{ ...S.btn("ghost"), fontSize: 10, padding: "2px 7px" }} title="Edit batch" onClick={() => startEditBatch(b)}>✏️</button>
                          <button style={{ ...S.btn("ghost"), fontSize: 10, padding: "2px 7px", color: T.danger }} title="Delete batch" onClick={() => setConfirm(b.id)}>🗑</button>
                        </>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Summary by meal */}
      {batches.length > 2 && (
        <div style={{ marginTop: 20 }}>
          <div style={{ fontSize: 12, fontWeight: 700, marginBottom: 8, color: T.textMuted }}>📊 Production Summary by Meal</div>
          <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "repeat(3, 1fr)", gap: 8 }}>
            {Object.entries(
              batches.reduce((acc, b) => {
                if (!acc[b.mealName]) acc[b.mealName] = { portions: 0, cost: 0, runs: 0 };
                acc[b.mealName].portions += b.portions;
                acc[b.mealName].cost += b.totalCost;
                acc[b.mealName].runs += 1;
                return acc;
              }, {})
            )
              .sort((a, b) => b[1].portions - a[1].portions)
              .map(([name, stats]) => (
                <div key={name} style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 8, padding: "10px 13px" }}>
                  <div style={{ fontWeight: 700, fontSize: 12, marginBottom: 4 }}>{name}</div>
                  <div style={{ fontSize: 11, color: T.textMuted, lineHeight: 1.8 }}>
                    <div>{stats.portions} portions across {stats.runs} run{stats.runs > 1 ? "s" : ""}</div>
                    <div>Total cost: <span style={{ color: T.warning }}>{fmt(stats.cost)}</span></div>
                    <div>Avg/portion: <span style={{ color: T.success }}>{fmt(stats.cost / stats.portions)}</span></div>
                  </div>
                </div>
              ))}
          </div>
        </div>
      )}
    </div>
  );
}

// ─── RESTAURANT & DELIVERY (with Meals tab) ─────────────────────
function RestaurantPage({
  sales,
  setSales,
  inventory,
  setInventory,
  catalogItems,
  meals,
  setMeals,
  batches,
  setBatches,
  logo,
  biz,
  customers,
  setCustomers,
}) {
  const [tab, setTab] = useState("orders");
  const [filterType, setFilterType] = useState("All");
  const [addSale, setAddSale] = useState(false);
  const [editSaleId, setEditSaleId] = useState(null);
  const [showNewCustomerInline, setShowNewCustomerInline] = useState(false);
  const [newCustExtra, setNewCustExtra] = useState({ email: "", classification: "Regular", notes: "" });
  const [doc, setDoc] = useState(null);
  const EMPTY = {
    date: TODAY_ISO,
    meal: "",
    mealId: null,
    plates: "",
    pricePerPlate: "",
    method: "Cash",
    type: "Delivery",
    deliveryFee: 0,
    deliveryAddress: "",
    clientName: "",
    clientPhone: "",
    notes: "",
    partialPaid: "",
  };
  const [ns, setNs] = useState(EMPTY);
  const [addingInv, setAddingInv] = useState(false);
  const [editInvId, setEditInvId] = useState(null);
  const [ni, setNi] = useState({
    name: "",
    category: "Ingredient",
    unit: "kg",
    stock: "",
    reorderAt: "",
    costPerUnit: "",
    linkedMeals: "",
  });
  const [invCategories, setInvCategories] = useState([
    "Ingredient", "Packaging", "Fuel", "Beverage", "Cleaning", "Other",
  ]);
  const [showNewCatInput, setShowNewCatInput] = useState(false);
  const [newCatValue, setNewCatValue] = useState("");
  // Meals state
  const [addingMeal, setAddingMeal] = useState(false);
  const [editMealId, setEditMealId] = useState(null);
  const EMPTY_MEAL = {
    name: "",
    description: "",
    price: "",
    category: "Main",
    photo: null,
    active: true,
    ingredientLinks: [],
    laborCost: "",
    otherCosts: [],
    availablePortions: "",
  };
  const [nm, setNm] = useState(EMPTY_MEAL);
  const [importFromCatalog, setImportFromCatalog] = useState(false);
  const [editIngLinks, setEditIngLinks] = useState(null); // meal id
  const [expandedMeal, setExpandedMeal] = useState(null); // meal id for costing panel
  const mealPhotoRef = useRef();
  const isMobile = useIsMobile();

  const openDoc = (title, html) =>
    setDoc({ title, html, onPrint: () => printDoc(title, html) });
  const filtered =
    filterType === "All" ? sales : sales.filter((s) => s.type === filterType);
  const todayRev = sales
    .filter((s) => s.date === TODAY_ISO)
    .reduce((s, r) => s + orderTotal(r), 0);
  const weekRev = sales.reduce((s, r) => s + orderTotal(r), 0);
  const delRev = sales
    .filter((s) => s.type === "Delivery")
    .reduce((s, r) => s + orderTotal(r), 0);
  const delFees = sales
    .filter((s) => s.type === "Delivery")
    .reduce((s, r) => s + (r.deliveryFee || 0), 0);

  const byMeal = {};
  sales.forEach((s) => {
    byMeal[s.meal] = (byMeal[s.meal] || 0) + s.plates * s.pricePerPlate;
  });
  const lowStock = inventory.filter((i) => i.stock <= i.reorderAt);
  const typeColor = {
    Delivery: T.delivery,
  };
  const totalStockValue = inventory.reduce(
    (s, i) => s + i.stock * i.costPerUnit,
    0
  );

  const saveSale = () => {
    const plates = Number(ns.plates);
    const sale = {
      ...ns,
      id: editSaleId || Date.now(),
      plates,
      pricePerPlate: Number(ns.pricePerPlate),
      deliveryFee: Number(ns.deliveryFee || 0),
    };

    if (editSaleId) {
      // Restore portions for the OLD sale before replacing
      const old = sales.find((s) => s.id === editSaleId);
      if (old && old.mealId) {
        setMeals((prev) =>
          prev.map((m) =>
            m.id === Number(old.mealId)
              ? { ...m, availablePortions: (Number(m.availablePortions) || 0) + Number(old.plates) }
              : m
          )
        );
      }
      setSales((prev) => prev.map((s) => s.id === editSaleId ? sale : s));
    } else {
      setSales((prev) => [...prev, sale]);
    }

    // Deduct availablePortions for the NEW/updated sale
    if (ns.mealId) {
      setMeals((prev) =>
        prev.map((m) =>
          m.id === Number(ns.mealId)
            ? { ...m, availablePortions: Math.max(0, (Number(m.availablePortions) || 0) - plates) }
            : m
        )
      );
    }

    // Legacy inventory deduction by meal name match (kept for backward compat, new saves only)
    if (!editSaleId) {
      setInventory((prev) =>
        prev.map((item) => {
          const mealLower = ns.meal.toLowerCase();
          const linked =
            Array.isArray(item.linkedMeals) &&
            item.linkedMeals.some(
              (m) =>
                mealLower.includes(m.toLowerCase().split(" ")[0]) ||
                m.toLowerCase().includes(mealLower.split(" ")[0])
            );
          if (linked && item.usedPerPlate > 0)
            return { ...item, stock: Math.max(0, item.stock - item.usedPerPlate * plates) };
          return item;
        })
      );
    }

    setAddSale(false);
    setEditSaleId(null);
    setNs(EMPTY);
    setShowNewCustomerInline(false);
    setNewCustExtra({ email: "", classification: "Regular", notes: "" });

    // Auto-upsert customer from order
    if (ns.clientName && ns.clientName.trim()) {
      const name = ns.clientName.trim();
      const phone = (ns.clientPhone || "").trim();
      setCustomers(prev => {
        const idx = prev.findIndex(c => c.name.toLowerCase() === name.toLowerCase());
        if (idx >= 0) {
          // Update phone if blank
          const updated = [...prev];
          updated[idx] = { ...updated[idx], phone: updated[idx].phone || phone };
          return updated;
        }
        return [...prev, { id: Date.now(), name, phone, email: "", classification: "Regular", notes: "", createdAt: TODAY_ISO }];
      });
    }
  };

  const deleteSale = (id) => {
    const s = sales.find((sale) => sale.id === id);
    if (!window.confirm("Delete this order? " + (s?.plates || "") + " unit(s) of " + (s?.meal || ""))) return;
    // Restore portions to the linked meal
    if (s?.mealId) {
      setMeals((prev) =>
        prev.map((m) =>
          m.id === Number(s.mealId)
            ? { ...m, availablePortions: (Number(m.availablePortions) || 0) + Number(s.plates) }
            : m
        )
      );
    }
    setSales((prev) => prev.filter((sale) => sale.id !== id));
  };

