    if (editMealId != null) {
      setMeals((prev) =>
        prev.map((m) => (m.id === editMealId ? { ...meal, id: editMealId } : m))
      );
      setEditMealId(null);
    } else {
      setMeals((prev) => [...prev, { ...meal, id: Date.now() }]);
    }
    setAddingMeal(false);
    setNm(EMPTY_MEAL);
  };
