  };
  const getMealIngCost = (meal) =>
    (meal.ingredientLinks || []).reduce((s, l) => {
      const inv = inventory.find((i) => i.id === l.inventoryId);
      return s + (inv ? inv.costPerUnit * l.qty : 0);
    }, 0);
  const getMealTotalCost = (meal) =>
    getMealIngCost(meal) +
    Number(meal.laborCost || 0) +
