                  {(() => {
                    // Compute live remaining portions per meal from batches minus sales (authoritative)
                    const mealPortions = {};
                    batches.forEach((b) => {
                      if (!b.mealId) return;
                      const sold = sales
                        .filter((s) => Number(s.mealId) === Number(b.mealId) && s.date >= b.date)
