                    value={((Number(ns.plates) || 0) * (Number(ns.pricePerPlate) || 0) + (Number(ns.deliveryFee) || 0)).toFixed(2)}
                  />
                </div>
                <div>
                  <label style={S.label}>Payment Method</label>
                  <select
                    style={S.select}
                    value={ns.method}
                    onChange={(e) => setNs({ ...ns, method: e.target.value })}
