                      setNm({ ...nm, availablePortions: e.target.value })
                    }
                    placeholder="e.g. 30"
                  />
                </div>
              </div>

              {/* Live cost summary */}
              {(Number(nm.price) > 0 ||
                Number(nm.laborCost) > 0 ||
                (nm.ingredientLinks || []).length > 0) &&
                (() => {
                  const ingC = (nm.ingredientLinks || []).reduce((s, l) => {
                    const inv = inventory.find((i) => i.id === l.inventoryId);
                    return s + (inv ? inv.costPerUnit * l.qty : 0);
                  }, 0);
                  const labC = Number(nm.laborCost || 0);
                  const othC = (nm.otherCosts || []).reduce(
                    (s, c) => s + Number(c.amount || 0),
                    0
                  );
                  const totalC = ingC + labC + othC;
                  const price = Number(nm.price || 0);
                  const portions = Number(nm.availablePortions || 0);
                  const profit = price - totalC;
                  const margin =
                    price > 0 ? ((profit / price) * 100).toFixed(0) : null;
                  const totalValue = price * portions;
                  const totalProfit = profit * portions;
                  return (
                    <div
                      style={{
                        marginTop: 12,
                        background: T.surface,
                        borderRadius: 8,
                        padding: 12,
                        display: "grid",
                        gridTemplateColumns: "repeat(4,1fr)",
                        gap: 10,
                      }}
                    >
                      <div>
                        <div
                          style={{
                            fontSize: 10,
                            color: T.textMuted,
                            marginBottom: 2,
                          }}
                        >
                          Total Cost/Portion
                        </div>
                        <div
                          style={{
                            fontSize: 14,
                            fontWeight: 800,
                            color: T.danger,
                          }}
                        >
                          {fmt(totalC)}
                        </div>
                      </div>
                      <div>
                        <div
                          style={{
                            fontSize: 10,
                            color: T.textMuted,
                            marginBottom: 2,
                          }}
                        >
                          Profit/Portion
                        </div>
                        <div
                          style={{
                            fontSize: 14,
                            fontWeight: 800,
                            color: profit >= 0 ? T.success : T.danger,
                          }}
                        >
                          {fmt(profit)}
                        </div>
                        {margin && (
                          <div style={{ fontSize: 9, color: T.textMuted }}>
                            {margin}% margin
                          </div>
                        )}
                      </div>
                      <div>
                        <div
                          style={{
                            fontSize: 10,
                            color: T.textMuted,
                            marginBottom: 2,
                          }}
                        >
                          Total Meal Value
                        </div>
                        <div
                          style={{
                            fontSize: 14,
                            fontWeight: 800,
                            color: T.accent,
                          }}
                        >
                          {portions > 0 ? fmt(totalValue) : "—"}
                        </div>
                        {portions > 0 && (
                          <div style={{ fontSize: 9, color: T.textMuted }}>
                            {portions} portions × {fmt(price)}
                          </div>
                        )}
                      </div>
                      <div>
                        <div
                          style={{
                            fontSize: 10,
                            color: T.textMuted,
                            marginBottom: 2,
                          }}
                        >
                          Total Profit
                        </div>
                        <div
                          style={{
                            fontSize: 14,
                            fontWeight: 800,
                            color: totalProfit >= 0 ? T.success : T.danger,
                          }}
                        >
                          {portions > 0 ? fmt(totalProfit) : "—"}
                        </div>
                      </div>
                    </div>
                  );
                })()}

              <div
                style={{ ...S.row, marginTop: 12, justifyContent: "flex-end" }}
              >
                <button
                  style={S.btn("ghost")}
                  onClick={() => {
                    setAddingMeal(false);
                    setEditMealId(null);
                    setNm(EMPTY_MEAL);
                  }}
                >
                  Cancel
                </button>
                <button style={S.btn("primary")} onClick={saveMeal}>
                  {editMealId ? "Update Meal" : "Save Meal"}
                </button>
              </div>
            </div>
          )}

          {/* Meals list */}
          <div style={isMobile ? S.gridMobile : S.grid(3)}>
            {meals.map((meal) => {
              const ingCost = getMealIngCost(meal);
              const totalCost = getMealTotalCost(meal);
              const portions = Number(meal.availablePortions || 0);
              const profit = meal.price - totalCost;
              const margin =
                meal.price > 0 && totalCost > 0
                  ? (((meal.price - totalCost) / meal.price) * 100).toFixed(0)
                  : null;
              const totalValue = meal.price * portions;
              const totalProfit = profit * portions;
              const isExpanded = expandedMeal === meal.id;
              const marginColor = margin
                ? Number(margin) > 40
                  ? T.success
                  : Number(margin) > 20
                  ? T.warning
                  : T.danger
                : T.textMuted;
              return (
                <div
                  key={meal.id}
                  style={{
                    ...S.card,
                    padding: 0,
                    overflow: "hidden",
                    opacity: meal.active ? 1 : 0.6,
                  }}
                >
                  {/* Photo */}
                  <div
                    style={{
                      height: 90,
                      background: T.surface,
                      position: "relative",
                      cursor: "pointer",
                    }}
                    onClick={() => {
                      const inp = document.createElement("input");
                      inp.type = "file";
                      inp.accept = "image/*";
                      inp.onchange = (e) => {
                        const f = e.target.files[0];
                        if (!f) return;
                        const r = new FileReader();
                        r.onload = (ev) =>
                          setMeals((prev) =>
                            prev.map((m) =>
                              m.id === meal.id
                                ? { ...m, photo: ev.target.result }
                                : m
                            )
                          );
                        r.readAsDataURL(f);
                      };
                      inp.click();
                    }}
                  >
                    {meal.photo ? (
                      <img
                        src={meal.photo}
                        alt={meal.name}
                        style={{
                          width: "100%",
                          height: "100%",
                          objectFit: "cover",
                        }}
                      />
                    ) : (
                      <div
                        style={{
                          height: "100%",
                          display: "flex",
                          flexDirection: "column",
                          alignItems: "center",
                          justifyContent: "center",
                          color: T.textDim,
                          gap: 2,
                        }}
                      >
                        <div style={{ fontSize: 24 }}>🍽️</div>
                        <div style={{ fontSize: 9 }}>Click to upload</div>
                      </div>
                    )}
                    {!meal.active && (
                      <div
                        style={{
                          position: "absolute",
                          top: 4,
                          left: 4,
                          background: T.danger,
                          color: "#fff",
                          fontSize: 9,
                          padding: "2px 5px",
                          borderRadius: 3,
                        }}
                      >
                        INACTIVE
                      </div>
                    )}
                    <div
                      style={{
                        position: "absolute",
                        bottom: 4,
                        right: 4,
                        background: "rgba(0,0,0,0.55)",
                        color: "#fff",
                        fontSize: 8,
                        padding: "2px 4px",
                        borderRadius: 3,
                      }}
                    >
                      📷
                    </div>
                  </div>

                  <div style={{ padding: 10 }}>
                    {/* Name & category */}
                    <div
                      style={{
                        display: "flex",
                        justifyContent: "space-between",
                        alignItems: "flex-start",
                        marginBottom: 2,
                      }}
                    >
                      <div style={{ fontSize: 12, fontWeight: 700 }}>
                        {meal.name}
                      </div>
                      <Badge color={T.textMuted}>{meal.category}</Badge>
                    </div>
                    {meal.description && (
                      <div
                        style={{
                          fontSize: 10,
                          color: T.textDim,
                          marginBottom: 6,
                          lineHeight: 1.4,
                        }}
                      >
                        {meal.description}
                      </div>
                    )}

                    {/* Price row */}
                    <div
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: 6,
                        marginBottom: 4,
                      }}
                    >
                      <input
                        type="number"
                        value={meal.price}
                        onChange={(e) =>
                          setMeals((prev) =>
                            prev.map((m) =>
                              m.id === meal.id
                                ? { ...m, price: Number(e.target.value) }
                                : m
                            )
                          )
                        }
                        style={{
                          ...S.input,
                          width: 90,
                          padding: "3px 5px",
                          fontSize: 13,
                          fontWeight: 800,
                          color: T.accent,
                        }}
                      />
                      <span style={{ fontSize: 10, color: T.textMuted }}>
                        USD/portion
                      </span>
                    </div>

                    {/* Quick cost summary bar */}
                    <div
                      style={{
                        background: T.surface,
                        borderRadius: 6,
                        padding: "6px 8px",
                        marginBottom: 6,
                        fontSize: 10,
                      }}
                    >
                      <div
                        style={{
                          display: "flex",
                          justifyContent: "space-between",
                          marginBottom: 2,
                        }}
                      >
                        <span style={{ color: T.textMuted }}>
                          Cost/portion:
                        </span>
                        <span style={{ color: T.danger, fontWeight: 700 }}>
                          {totalCost > 0 ? fmt(totalCost) : "—"}
                        </span>
                      </div>
                      <div
                        style={{
                          display: "flex",
                          justifyContent: "space-between",
                          marginBottom: 2,
                        }}
                      >
                        <span style={{ color: T.textMuted }}>
                          Profit/portion:
                        </span>
                        <span
                          style={{
                            color: profit >= 0 ? T.success : T.danger,
                            fontWeight: 700,
                          }}
                        >
                          {totalCost > 0 ? fmt(profit) : "—"}
                        </span>
                      </div>
                      {margin && (
                        <div
                          style={{
                            display: "flex",
                            justifyContent: "space-between",
                            marginBottom: 2,
                          }}
                        >
                          <span style={{ color: T.textMuted }}>Margin:</span>
                          <span style={{ color: marginColor, fontWeight: 700 }}>
                            {margin}%
                          </span>
                        </div>
                      )}
                      <div
                        style={{
                          borderTop: `1px solid ${T.border}30`,
                          marginTop: 4,
                          paddingTop: 4,
                          display: "flex",
                          justifyContent: "space-between",
                        }}
                      >
                        <span style={{ color: T.textMuted }}>
                          {portions > 0
                            ? `${portions} portions available`
                            : "Portions not set"}
                        </span>
                      </div>
                      {portions > 0 && (
                        <>
                          <div
                            style={{
                              display: "flex",
                              justifyContent: "space-between",
                              marginTop: 2,
                            }}
                          >
                            <span style={{ color: T.textMuted }}>
                              Total value:
                            </span>
                            <span style={{ color: T.accent, fontWeight: 700 }}>
                              {fmt(totalValue)}
                            </span>
                          </div>
                          <div
                            style={{
                              display: "flex",
                              justifyContent: "space-between",
                              marginTop: 2,
                            }}
                          >
                            <span style={{ color: T.textMuted }}>
                              Total profit:
                            </span>
                            <span
                              style={{
                                color: totalProfit >= 0 ? T.success : T.danger,
                                fontWeight: 700,
                              }}
                            >
                              {fmt(totalProfit)}
                            </span>
                          </div>
                        </>
                      )}
                    </div>

                    {/* Expanded costing detail */}
                    {isExpanded && (
                      <div
                        style={{
                          background: `${T.surface}88`,
                          borderRadius: 6,
                          padding: 8,
                          marginBottom: 6,
                          fontSize: 10,
                        }}
                      >
                        {(meal.ingredientLinks || []).length > 0 && (
                          <>
                            <div
                              style={{
                                fontWeight: 700,
                                color: T.textMuted,
                                marginBottom: 4,
                              }}
                            >
                              🧂 Ingredients
                            </div>
                            {meal.ingredientLinks.map((l) => {
                              const inv = inventory.find(
                                (i) => i.id === l.inventoryId
                              );
                              if (!inv) return null;
                              return (
                                <div
                                  key={l.inventoryId}
                                  style={{
                                    display: "flex",
                                    justifyContent: "space-between",
                                    marginBottom: 2,
                                  }}
                                >
                                  <span style={{ color: T.textDim }}>
                                    {inv.name} × {l.qty}
                                    {inv.unit}
                                  </span>
                                  <span style={{ color: T.danger }}>
                                    {fmt(inv.costPerUnit * l.qty)}
                                  </span>
                                </div>
                              );
                            })}
                            <div
                              style={{
                                display: "flex",
                                justifyContent: "space-between",
                                borderTop: `1px solid ${T.border}30`,
                                marginTop: 3,
                                paddingTop: 3,
                                fontWeight: 700,
                              }}
                            >
                              <span style={{ color: T.textMuted }}>
                                Ingredients subtotal
                              </span>
                              <span style={{ color: T.danger }}>
                                {fmt(ingCost)}
                              </span>
                            </div>
                          </>
                        )}
                        {Number(meal.laborCost || 0) > 0 && (
                          <div
                            style={{
                              display: "flex",
                              justifyContent: "space-between",
                              marginTop: 4,
                            }}
                          >
                            <span style={{ color: T.textMuted }}>👨‍🍳 Labor</span>
                            <span style={{ color: T.danger }}>
                              {fmt(meal.laborCost)}
                            </span>
                          </div>
                        )}
                        {(meal.otherCosts || [])
                          .filter((c) => Number(c.amount) > 0)
                          .map((c, i) => (
                            <div
                              key={i}
                              style={{
                                display: "flex",
                                justifyContent: "space-between",
                                marginTop: 2,
                              }}
                            >
                              <span style={{ color: T.textMuted }}>
                                📋 {c.label || "Other"}
                              </span>
                              <span style={{ color: T.danger }}>
                                {fmt(c.amount)}
                              </span>
                            </div>
                          ))}
                        <div
                          style={{
                            display: "flex",
                            justifyContent: "space-between",
                            borderTop: `1px solid ${T.border}`,
                            marginTop: 5,
                            paddingTop: 5,
                            fontWeight: 800,
                          }}
                        >
                          <span style={{ color: T.text }}>Total Cost</span>
                          <span style={{ color: T.danger }}>
                            {fmt(totalCost)}
                          </span>
                        </div>
                      </div>
                    )}

                    {/* Action buttons */}
                    <div style={{ display: "flex", gap: 4, flexWrap: "wrap" }}>
                      <button
                        style={{
                          ...S.btn("ghost"),
                          fontSize: 9,
                          padding: "2px 6px",
                        }}
                        onClick={() => startEditMeal(meal)}
                      >
                        ✏️ Edit
                      </button>
                      <button
                        style={{
                          ...S.btn("ghost"),
                          fontSize: 9,
                          padding: "2px 6px",
                          borderColor: isExpanded ? T.accent : T.border,
                          color: isExpanded ? T.accent : T.text,
                        }}
                        onClick={() =>
                          setExpandedMeal(isExpanded ? null : meal.id)
                        }
                      >
                        💰 {isExpanded ? "Hide Cost" : "View Cost"}
                      </button>
                      <button
                        style={{
                          ...S.btn("ghost"),
                          fontSize: 9,
                          padding: "2px 6px",
                          color: meal.active ? T.danger : T.success,
                        }}
                        onClick={() =>
                          setMeals((prev) =>
                            prev.map((m) =>
                              m.id === meal.id ? { ...m, active: !m.active } : m
                            )
                          )
                        }
                      >
                        {meal.active ? "Deactivate" : "Activate"}
                      </button>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
          {meals.length === 0 && (
            <div
              style={{ color: T.textMuted, padding: 30, textAlign: "center" }}
            >
              No meals yet. Add a new meal or import from the catalog.
            </div>
          )}
        </>
      )}

      {/* ── INVENTORY TAB ── */}
      {tab === "inventory" && (
        <>
          <div style={{ ...S.row, marginBottom: 12, flexWrap: "wrap", gap: 6 }}>
            <div style={{ ...S.card, flex: 1, padding: 10, minWidth: 180 }}>
              <div style={S.cardTitle}>Total Supplies Value</div>
              <div style={{ ...S.kpi, fontSize: 18 }}>
                {fmt(totalStockValue)}
              </div>
            </div>
            <div style={{ ...S.card, flex: 1, padding: 10, minWidth: 180 }}>
              <div style={S.cardTitle}>Low Stock Items</div>
              <div
                style={{
                  ...S.kpi,
                  fontSize: 18,
                  color: lowStock.length > 0 ? T.danger : T.success,
                }}
              >
                {lowStock.length}
              </div>
            </div>
            <div style={{ ...S.card, flex: 1, padding: 10, minWidth: 180 }}>
              <div style={S.cardTitle}>Total Items</div>
              <div style={{ ...S.kpi, fontSize: 18 }}>{inventory.length}</div>
            </div>
            <button
              style={{ ...S.btn("primary"), alignSelf: "center" }}
              onClick={() => {
                setAddingInv(!addingInv);
                setEditInvId(null);
                setShowNewCatInput(false);
                setNewCatValue("");
                setNi({
                  name: "",
                  category: "Ingredient",
                  unit: "kg",
                  stock: "",
                  reorderAt: "",
                  costPerUnit: "",
                  linkedMeals: "",
                });
              }}
            >
              + Add Item
            </button>
          </div>
          {addingInv && (
            <div style={{ ...S.card, marginBottom: 12, borderColor: T.accent }}>
              <div style={S.sectionTitle}>
                {editInvId != null
                  ? "Edit Inventory Item"
                  : "New Inventory Item"}
              </div>
              <div style={S.grid(4)}>
                <div>
                  <label style={S.label}>Item Name</label>
                  <input
                    style={S.input}
                    value={ni.name}
                    onChange={(e) => setNi({ ...ni, name: e.target.value })}
                  />
                </div>
                <div>
                  <label style={S.label}>Category</label>
                  {showNewCatInput ? (
                    <div style={{ display: "flex", gap: 4 }}>
                      <input
                        style={{ ...S.input, flex: 1 }}
                        autoFocus
                        placeholder="New category name…"
                        value={newCatValue}
                        onChange={(e) => setNewCatValue(e.target.value)}
                        onKeyDown={(e) => {
                          if (e.key === "Enter") {
                            const trimmed = newCatValue.trim();
                            if (trimmed && !invCategories.includes(trimmed)) {
                              setInvCategories((prev) => [...prev, trimmed]);
                              setNi({ ...ni, category: trimmed });
                            } else if (trimmed) {
                              setNi({ ...ni, category: trimmed });
                            }
                            setNewCatValue("");
                            setShowNewCatInput(false);
                          }
                          if (e.key === "Escape") {
                            setNewCatValue("");
                            setShowNewCatInput(false);
                          }
                        }}
                      />
                      <button
                        style={{ ...S.btn("primary"), padding: "4px 8px", fontSize: 11 }}
                        onClick={() => {
                          const trimmed = newCatValue.trim();
                          if (trimmed && !invCategories.includes(trimmed)) {
                            setInvCategories((prev) => [...prev, trimmed]);
                            setNi({ ...ni, category: trimmed });
                          } else if (trimmed) {
                            setNi({ ...ni, category: trimmed });
                          }
                          setNewCatValue("");
                          setShowNewCatInput(false);
                        }}
                      >
                        ✓
                      </button>
                      <button
                        style={{ ...S.btn("ghost"), padding: "4px 8px", fontSize: 11 }}
                        onClick={() => { setNewCatValue(""); setShowNewCatInput(false); }}
                      >
                        ✕
                      </button>
                    </div>
                  ) : (
                    <div style={{ display: "flex", gap: 4 }}>
                      <select
                        style={{ ...S.select, flex: 1 }}
                        value={ni.category}
                        onChange={(e) => setNi({ ...ni, category: e.target.value })}
                      >
                        {invCategories.map((c) => (
                          <option key={c}>{c}</option>
                        ))}
                      </select>
                      <button
                        title="Add new category"
                        style={{
                          ...S.btn("ghost"),
                          padding: "4px 8px",
                          fontSize: 13,
                          flexShrink: 0,
                          borderColor: T.accent,
                          color: T.accent,
                        }}
                        onClick={() => setShowNewCatInput(true)}
                      >
                        +
                      </button>
                    </div>
                  )}
                </div>
                <div>
                  <label style={S.label}>Unit</label>
                  <input
                    style={S.input}
                    value={ni.unit}
                    placeholder="kg, L, pack…"
                    onChange={(e) => setNi({ ...ni, unit: e.target.value })}
                  />
                </div>
                <div>
                  <label style={S.label}>Current Stock</label>
                  <input
                    type="number"
                    style={S.input}
                    value={ni.stock}
                    onChange={(e) => setNi({ ...ni, stock: e.target.value })}
                  />
                </div>
                <div>
                  <label style={S.label}>Reorder At (min)</label>
                  <input
                    type="number"
                    style={S.input}
                    value={ni.reorderAt}
                    onChange={(e) =>
                      setNi({ ...ni, reorderAt: e.target.value })
                    }
                  />
                </div>
                <div>
                  <label style={S.label}>Cost per Unit (USD)</label>
                  <input
                    type="number"
                    style={S.input}
                    value={ni.costPerUnit}
                    onChange={(e) =>
                      setNi({ ...ni, costPerUnit: e.target.value })
                    }
                  />
                </div>

                <div>
                  <label style={S.label}>Linked Meals (comma-sep.)</label>
                  <input
                    style={S.input}
                    value={ni.linkedMeals}
                    placeholder="e.g. Rice & Chicken, Stew…"
                    onChange={(e) =>
                      setNi({ ...ni, linkedMeals: e.target.value })
                    }
                  />
                </div>
              </div>
              <div
                style={{ ...S.row, marginTop: 10, justifyContent: "flex-end" }}
              >
                <button
                  style={S.btn("ghost")}
                  onClick={() => {
                    setAddingInv(false);
                    setEditInvId(null);
                    setShowNewCatInput(false);
                    setNewCatValue("");
                  }}
                >
                  Cancel
                </button>
                <button style={S.btn("primary")} onClick={saveInv}>
                  {editInvId != null ? "Update" : "Add to Inventory"}
                </button>
              </div>
            </div>
          )}
          {lowStock.length > 0 && (
            <div style={{ background:`${T.danger}0D`, border:`1.5px solid ${T.danger}50`, borderRadius:8, padding:"10px 14px", marginBottom:12 }}>
              <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:8 }}>
                <span style={{ fontSize:16 }}>🚨</span>
                <strong style={{ color:T.danger, fontSize:12 }}>Reorder Needed — {lowStock.length} item{lowStock.length!==1?"s":""} below threshold</strong>
              </div>
              <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))", gap:6 }}>
                {lowStock.map(item => (
                  <div key={item.id} style={{ background:`${T.danger}0A`, border:`1px solid ${item.stock===0?T.danger:T.warning}60`, borderRadius:6, padding:"6px 10px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                    <div>
                      <div style={{ fontSize:11, fontWeight:700, color:T.text }}>{item.name}</div>
                      <div style={{ fontSize:10, color:T.textMuted }}>Min: {item.reorderAt} {item.unit}</div>
                    </div>
                    <div style={{ textAlign:"right", flexShrink:0 }}>
                      <div style={{ fontSize:13, fontWeight:900, color:item.stock===0?T.danger:T.warning }}>{item.stock}</div>
                      <div style={{ fontSize:9, color:T.textMuted }}>{item.unit} left</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
          <div className="tbl-wrap">
            <table style={S.table}>
              <thead>
                <tr>
                  {[
                    "Item",
                    "Category",
                    "Unit",
                    "Stock",
                    "Reorder At",
                    "Cost/Unit",
                    "Stock Value",
                    "Linked Meals",
                    "Status",
                    "",
                  ].map((h) => (
                    <th key={h} style={S.th}>
                      {h}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {inventory.map((item) => {
                  const low = item.stock <= item.reorderAt;

                  return (
                    <tr key={item.id}>
                      <td style={{ ...S.td, fontWeight: 700 }}>{item.name}</td>
                      <td style={S.td}>{item.category}</td>
                      <td style={S.td}>{item.unit}</td>
                      <td
                        style={{
                          ...S.td,
                          fontWeight: 700,
                          color: low ? T.danger : T.success,
                        }}
                      >
                        {Math.round(item.stock * 100) / 100}
                      </td>
                      <td style={S.td}>{item.reorderAt}</td>
                      <td style={S.td}>{fmt(item.costPerUnit)}</td>

                      <td style={{ ...S.td, color: T.accent, fontWeight: 700 }}>
                        {fmt(item.stock * item.costPerUnit)}
                      </td>
                      <td style={{ ...S.td, fontSize: 11, color: T.textMuted }}>
                        {(item.linkedMeals || []).join(", ") || "—"}
                      </td>
                      <td style={S.td}>
                        {low ? (
                          <Badge color={T.danger}>Low</Badge>
                        ) : (
                          <Badge color={T.success}>OK</Badge>
                        )}
                      </td>
                      <td style={S.td}>
                        <div style={{ display: "flex", gap: 3 }}>
                          <button
                            style={{
                              ...S.btn("ghost"),
                              fontSize: 10,
                              padding: "2px 6px",
                            }}
                            onClick={() => startEditInv(item)}
                          >
                            Edit
                          </button>
                          <button
                            style={{
                              ...S.btn("ghost"),
                              fontSize: 10,
                              padding: "2px 6px",
                            }}
                            onClick={() => {
                              const qty = prompt(
                                `Restock ${item.name}\nCurrent: ${item.stock} ${item.unit}\nAdd quantity:`
                              );
                              if (qty && !isNaN(Number(qty)))
                                setInventory((prev) =>
                                  prev.map((it) =>
                                    it.id === item.id
                                      ? { ...it, stock: it.stock + Number(qty) }
                                      : it
                                  )
                                );
                            }}
                          >
                            + Restock
                          </button>
                          <button
                            style={{
                              background: "none",
                              border: "none",
                              color: T.danger,
                              cursor: "pointer",
                              fontSize: 11,
                            }}
                            onClick={() => {
                              if (window.confirm(`Delete ${item.name}?`))
                                deleteInv(item.id);
                            }}
                          >
                            ✕
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

        </>
      )}

      {tab === "batches" && (
        <BatchesTab
          batches={batches}
          setBatches={setBatches}
          meals={meals}
          setMeals={setMeals}
          inventory={inventory}
          setInventory={setInventory}
          getMealTotalCost={getMealTotalCost}
          sales={sales}
        />
      )}
    </div>
  );
}

// ─── INVOICES ─────────────────────────────────────────────────────
function InvoicesPage({ invoices, setInvoices, events, logo, biz }) {
  const [doc, setDoc] = useState(null);
  const openDoc = (title, html) =>
    setDoc({ title, html, onPrint: () => printDoc(title, html) });
  const totalAR = invoices.reduce((s, i) => s + (i.total - i.paid), 0);
  const totalPaid = invoices.reduce((s, i) => s + i.paid, 0);
  const recordPmt = (idx, amount) => {
    const u = [...invoices];
    const inv = { ...u[idx] };
    inv.paid = Math.min(inv.paid + Number(amount), inv.total);
    inv.status =
      inv.paid >= inv.total
        ? "Paid"
        : inv.paid > 0
        ? "Partially Paid"
        : "Unpaid";
    u[idx] = inv;
    setInvoices(u);
  };
  const stColor = {
    Paid: T.success,
    "Partially Paid": T.warning,
    Unpaid: T.danger,
    Cancelled: T.textDim,
  };
  return (
    <div>
      <DocModal doc={doc} onClose={() => setDoc(null)} />
      <div style={S.pageTitle}>🧾 Invoices & Payments</div>
      <div style={S.grid(4)}>
        <KpiCard
          label="AR Outstanding"
          value={fmt(totalAR)}
          color={T.danger}
          icon="⚠️"
        />
        <KpiCard
          label="Total Collected"
          value={fmt(totalPaid)}
          color={T.success}
          icon="✅"
        />
        <KpiCard
          label="Unpaid Invoices"
          value={invoices.filter((i) => i.status === "Unpaid").length}
          color={T.warning}
          icon="📬"
        />
        <KpiCard
          label="Total Invoiced"
          value={fmt(invoices.reduce((s, i) => s + i.total, 0))}
          icon="📄"
        />
      </div>
      <div style={{ marginTop: 14 }}>
        <div className="tbl-wrap">
          <table style={S.table}>
            <thead>
              <tr>
                {[
                  "Invoice #",
                  "Client",
                  "Issued",
                  "Due",
                  "Total",
                  "Paid",
                  "Balance",
                  "OD",
                  "Status",
                  "Documents",
                  "Action",
                ].map((h) => (
                  <th key={h} style={S.th}>
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {invoices.map((inv, i) => {
                const bal = inv.total - inv.paid;
                const od = daysOD(inv.due);
                const evt = events.find((e) => e.id === inv.eventId);
                return (
                  <tr key={inv.id}>
                    <td
                      style={{
                        ...S.td,
                        fontWeight: 700,
                        color: T.accent,
                        whiteSpace: "nowrap",
                      }}
                    >
                      {inv.num}
                    </td>
                    <td style={{ ...S.td, fontWeight: 700 }}>{inv.client}</td>
                    <td style={{ ...S.td, whiteSpace: "nowrap" }}>
                      {inv.issued}
                    </td>
                    <td style={{ ...S.td, whiteSpace: "nowrap" }}>{inv.due}</td>
                    <td style={{ ...S.td, fontWeight: 600 }}>
                      {fmt(inv.total)}
                    </td>
                    <td style={{ ...S.td, color: T.success }}>
                      {fmt(inv.paid)}
                    </td>
                    <td
                      style={{
                        ...S.td,
                        fontWeight: 700,
                        color: bal > 0 ? T.danger : T.success,
                      }}
                    >
                      {fmt(bal)}
                    </td>
                    <td
                      style={{
                        ...S.td,
                        color: od > 0 ? T.danger : T.success,
                        fontSize: 11,
                      }}
                    >
                      {od > 0 ? `${od}d` : "—"}
                    </td>
                    <td style={S.td}>
                      <Badge color={stColor[inv.status] || T.textMuted}>
                        {inv.status}
                      </Badge>
                    </td>
                    <td style={S.td}>
                      <div style={{ display: "flex", gap: 3 }}>
                        <button
                          style={{
                            ...S.btn("ghost"),
                            fontSize: 10,
                            padding: "3px 7px",
                          }}
                          onClick={() =>
                            openDoc(
                              `Invoice ${inv.num}`,
                              buildInvoiceHTML(inv, evt, biz, logo)
                            )
                          }
                        >
                          📄 Invoice
                        </button>
                        {inv.paid > 0 && (
                          <button
                            style={{
                              ...S.btn("ghost"),
                              fontSize: 10,
                              padding: "3px 7px",
                            }}
                            onClick={() =>
                              openDoc(
                                `Receipt ${inv.num.replace("INV", "RCT")}`,
                                buildReceiptHTML(inv, biz, logo)
                              )
                            }
                          >
                            🧾 Receipt
                          </button>
                        )}
                      </div>
                    </td>
                    <td style={S.td}>
                      {bal > 0 ? (
                        <div style={{ display:"flex", flexDirection:"column", gap:3 }}>
                          <button
                            style={{ ...S.btn("primary"), padding:"3px 8px", fontSize:10, whiteSpace:"nowrap" }}
                            onClick={() => {
                              const a = prompt(`Record payment – ${inv.num}\nBalance: ${fmt(bal)}\n\nEnter amount (USD):`);
                              if (a && !isNaN(Number(a))) recordPmt(i, a);
                            }}
                          >+ Pmt</button>
                          <button
                            style={{ ...S.btn("ghost"), padding:"3px 8px", fontSize:10, color:T.success, borderColor:T.success+"50", whiteSpace:"nowrap" }}
                            onClick={() => { if (window.confirm(`Mark ${inv.num} as fully paid?\nAmount: ${fmt(bal)}`)) recordPmt(i, String(bal)); }}
                          >✓ Paid in Full</button>
                        </div>
                      ) : (
                        <span style={{ fontSize:10, color:T.success, fontWeight:700 }}>✅ Paid</span>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        <div style={{ ...S.card, marginTop: 10 }}>
          <div style={S.cardTitle}>AR Aging Detail</div>
          {invoices
            .filter((i) => i.total - i.paid > 0)
            .map((inv, i) => {
              const bal = inv.total - inv.paid;
              const days = daysOD(inv.due);
              const b = ageBucket(days);
              const bc = {
                Current: T.success,
                "1–7 days": T.warning,
                "8–30 days": T.warning,
                "31–60 days": T.danger,
                "61+ days": T.danger,
              }[b];
              return (
                <div
                  key={i}
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    padding: "7px 0",
                    borderBottom: `1px solid ${T.border}15`,
                  }}
                >
                  <div>
                    <span
                      style={{ fontWeight: 700, fontSize: 12, marginRight: 6 }}
                    >
                      {inv.client}
                    </span>
                    <span style={{ fontSize: 11, color: T.textMuted }}>
                      {inv.num}
                    </span>
                  </div>
                  <div
                    style={{ display: "flex", gap: 10, alignItems: "center" }}
                  >
                    <Badge color={bc}>{b}</Badge>
                    <span
                      style={{ fontWeight: 800, color: T.danger, fontSize: 12 }}
                    >
                      {fmt(bal)}
                    </span>
                  </div>
                </div>
              );
            })}
        </div>
      </div>
    </div>
  );
}

// ─── CUSTOMERS PAGE ───────────────────────────────────────────────
const CUSTOMER_CLASSES = ["Regular", "VIP", "Wholesale", "Corporate", "Walk-in", "Blacklisted"];

function CustomersPage({ customers, setCustomers, invoices, setInvoices, events, sales, logo, biz }) {
  const [subTab, setSubTab] = useState("list");
  const [selCust, setSelCust] = useState(null);
  const [adding, setAdding] = useState(false);
  const [editId, setEditId] = useState(null);
  const [filterClass, setFilterClass] = useState("All");
  const [searchQ, setSearchQ] = useState("");
  const [doc, setDoc] = useState(null);
  const isMobile = useIsMobile();
  const openDoc = (title, html) => setDoc({ title, html, onPrint: () => printDoc(title, html) });

  const EMPTY_C = { name: "", phone: "", email: "", classification: "Regular", notes: "" };
  const [form, setForm] = useState(EMPTY_C);

  // Invoice state (moved from InvoicesPage)
  const totalAR = invoices.reduce((s, i) => s + (i.total - i.paid), 0);
  const totalPaid = invoices.reduce((s, i) => s + i.paid, 0);
  const recordPmt = (idx, amount) => {
    const u = [...invoices];
    const inv = { ...u[idx] };
    inv.paid = Math.min(inv.paid + Number(amount), inv.total);
    inv.status = inv.paid >= inv.total ? "Paid" : inv.paid > 0 ? "Partially Paid" : "Unpaid";
    u[idx] = inv;
    setInvoices(u);
  };
  const stColor = { Paid: T.success, "Partially Paid": T.warning, Unpaid: T.danger, Cancelled: T.textDim };

  const filtered = customers.filter(c => {
    if (filterClass !== "All" && c.classification !== filterClass) return false;
    if (searchQ && !c.name.toLowerCase().includes(searchQ.toLowerCase()) && !(c.phone || "").includes(searchQ)) return false;
    return true;
  });

  const saveCustomer = () => {
    if (!form.name.trim()) return;
    const item = { ...form, name: form.name.trim() };
    if (editId != null) {
      setCustomers(prev => prev.map(c => c.id === editId ? { ...item, id: editId } : c));
      setEditId(null);
    } else {
      setCustomers(prev => [...prev, { ...item, id: Date.now(), createdAt: TODAY_ISO }]);
    }
    setAdding(false);
    setForm(EMPTY_C);
  };

  const deleteCustomer = (id) => {
    if (!window.confirm("Delete this customer?")) return;
    setCustomers(prev => prev.filter(c => c.id !== id));
    if (selCust === id) setSelCust(null);
  };

  // Get activity for a customer
  const custSales = (name) => sales.filter(s => s.clientName && s.clientName.toLowerCase() === name.toLowerCase());
  const custEvents = (name) => events.filter(e => e.clientName && e.clientName.toLowerCase() === name.toLowerCase());
  const custInvoices = (name) => invoices.filter(i => i.client && i.client.toLowerCase() === name.toLowerCase());
  const custTotalSpend = (name) => {
    const sTotal = custSales(name).reduce((s, r) => s + orderTotal(r), 0);
    const eTotal = custEvents(name).reduce((s, e) => s + (e.revenue || 0), 0);
    const iTotal = custInvoices(name).reduce((s, i) => s + i.total, 0);
    return sTotal + eTotal + iTotal;
  };

  const classColor = { Regular: T.info, VIP: "#FFD700", Wholesale: T.catering, Corporate: T.accent, "Walk-in": T.textDim, Blacklisted: T.danger };
  const selCustomer = selCust != null ? customers.find(c => c.id === selCust) : null;

  return (
    <div>
      <DocModal doc={doc} onClose={() => setDoc(null)} />
      <div style={S.pageTitle}>👥 Customer Management</div>

      {/* Sub-tabs */}
      <div style={{ ...S.row, marginBottom: 14, flexWrap: "wrap", gap: 6 }}>
        {[["list", "👤 Customers"], ["invoices", "🧾 Invoices & AR"], ["ar", "💳 AR Overview"]].map(([v, l]) => (
          <button key={v} style={{ ...S.btn(subTab === v ? "primary" : "ghost"), fontSize: 13 }} onClick={() => setSubTab(v)}>{l}</button>
        ))}
      </div>

      {/* ── CUSTOMERS LIST ── */}
      {subTab === "list" && (
        <div>
          <div style={{ ...S.row, marginBottom: 10, flexWrap: "wrap", gap: 8 }}>
            <input style={{ ...S.input, width: 200 }} placeholder="Search name or phone…" value={searchQ} onChange={e => setSearchQ(e.target.value)} />
            <select style={S.select} value={filterClass} onChange={e => setFilterClass(e.target.value)}>
              <option value="All">All Types</option>
              {CUSTOMER_CLASSES.map(c => <option key={c}>{c}</option>)}
            </select>
            <button style={S.btn("primary")} onClick={() => { setAdding(true); setEditId(null); setForm(EMPTY_C); }}>+ Add Customer</button>
          </div>

          <div style={S.grid(4)}>
            <KpiCard label="Total Customers" value={customers.length} icon="👥" />
            <KpiCard label="VIP Clients" value={customers.filter(c => c.classification === "VIP").length} color="#FFD700" icon="⭐" />
            <KpiCard label="Corporate" value={customers.filter(c => c.classification === "Corporate").length} color={T.accent} icon="🏢" />
            <KpiCard label="AR Outstanding" value={fmt(totalAR)} color={T.danger} icon="⚠️" />
          </div>

          {adding && (
            <div style={{ ...S.card, marginTop: 12, borderColor: T.accent }}>
              <div style={S.sectionTitle}>{editId ? "Edit Customer" : "New Customer"}</div>
              <div style={S.grid(3)}>
                <div>
                  <label style={S.label}>Name *</label>
                  <input style={S.input} value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} placeholder="Full name" />
                </div>
                <div>
                  <label style={S.label}>Phone</label>
                  <input style={S.input} value={form.phone} onChange={e => setForm({ ...form, phone: e.target.value })} placeholder="+1 (704) 555-0100" />
                </div>
                <div>
                  <label style={S.label}>Email</label>
                  <input style={S.input} value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} placeholder="optional" />
                </div>
                <div>
                  <label style={S.label}>Classification</label>
                  <select style={S.select} value={form.classification} onChange={e => setForm({ ...form, classification: e.target.value })}>
                    {CUSTOMER_CLASSES.map(c => <option key={c}>{c}</option>)}
                  </select>
                </div>
                <div style={{ gridColumn: "span 2" }}>
                  <label style={S.label}>Notes</label>
                  <input style={S.input} value={form.notes} onChange={e => setForm({ ...form, notes: e.target.value })} placeholder="Allergies, preferences, etc." />
                </div>
              </div>
              <div style={{ ...S.row, marginTop: 10, justifyContent: "flex-end", gap: 8 }}>
                <button style={S.btn("ghost")} onClick={() => { setAdding(false); setEditId(null); setForm(EMPTY_C); }}>Cancel</button>
                <button style={S.btn("primary")} onClick={saveCustomer}>Save</button>
              </div>
            </div>
          )}

          {/* Customer detail panel */}
          {selCustomer && (
            <div style={{ ...S.card, marginTop: 12, borderColor: classColor[selCustomer.classification] || T.accent }}>
              <div style={{ ...S.row, justifyContent: "space-between", marginBottom: 8 }}>
                <div>
                  <span style={{ fontWeight: 700, fontSize: 16 }}>{selCustomer.name}</span>
                  {" "}<span style={{ background: classColor[selCustomer.classification] || T.info, color: "#fff", borderRadius: 10, padding: "2px 10px", fontSize: 11, marginLeft: 6 }}>{selCustomer.classification}</span>
                </div>
                <button style={S.btn("ghost")} onClick={() => setSelCust(null)}>✕ Close</button>
              </div>
              <div style={{ ...S.grid(3), marginBottom: 10 }}>
                <div><span style={{ color: T.textDim, fontSize: 12 }}>Phone</span><br />{selCustomer.phone || "—"}</div>
                <div><span style={{ color: T.textDim, fontSize: 12 }}>Email</span><br />{selCustomer.email || "—"}</div>
                <div><span style={{ color: T.textDim, fontSize: 12 }}>Since</span><br />{selCustomer.createdAt || "—"}</div>
                <div><span style={{ color: T.textDim, fontSize: 12 }}>Notes</span><br />{selCustomer.notes || "—"}</div>
                <div><span style={{ color: T.textDim, fontSize: 12 }}>Total Spend</span><br /><strong style={{ color: T.success }}>{fmt(custTotalSpend(selCustomer.name))}</strong></div>
              </div>
              <div style={S.sectionTitle}>Home Orders ({custSales(selCustomer.name).length})</div>
              {custSales(selCustomer.name).length === 0 ? <div style={{ color: T.textDim, fontSize: 13, marginBottom: 8 }}>No home orders.</div> : (
                <table style={{ ...S.table, marginBottom: 10 }}>
                  <thead><tr>{["Date","Meal","Products","Total","Paid","Balance","Notes"].map(h => <th key={h} style={S.th}>{h}</th>)}</tr></thead>
                  <tbody>{custSales(selCustomer.name).map(s => {
                    const tot = orderTotal(s);
                    const paid = s.partialPaid !== "" && s.partialPaid != null ? Number(s.partialPaid) : tot;
                    const bal = tot - paid;
                    return <tr key={s.id}>
                      <td style={S.td}>{s.date}</td>
                      <td style={S.td}>{s.meal}</td>
                      <td style={S.td}>{s.plates}</td>
                      <td style={S.td}>{fmt(tot)}</td>
                      <td style={{ ...S.td, color: T.success }}>{fmt(paid)}</td>
                      <td style={{ ...S.td, color: bal > 0 ? T.danger : T.success, fontWeight: bal > 0 ? 700 : 400 }}>{fmt(bal)}</td>
                      <td style={{ ...S.td, color: T.textDim, fontSize: 12 }}>{s.notes || "—"}</td>
                    </tr>;
                  })}</tbody>
                </table>
              )}
              <div style={S.sectionTitle}>Catering Events ({custEvents(selCustomer.name).length})</div>
              {custEvents(selCustomer.name).length === 0 ? <div style={{ color: T.textDim, fontSize: 13, marginBottom: 8 }}>No catering events.</div> : (
                <table style={{ ...S.table, marginBottom: 10 }}>
                  <thead><tr>{["Date","Event","Guests","Revenue","Phase"].map(h => <th key={h} style={S.th}>{h}</th>)}</tr></thead>
                  <tbody>{custEvents(selCustomer.name).map(e => (
                    <tr key={e.id}>
                      <td style={S.td}>{e.eventDate}</td>
                      <td style={S.td}>{e.name}</td>
                      <td style={S.td}>{e.guests}</td>
                      <td style={{ ...S.td, color: T.success, fontWeight: 600 }}>{fmt(e.revenue || 0)}</td>
                      <td style={S.td}>{e.phase}</td>
                    </tr>
                  ))}</tbody>
                </table>
              )}
              <div style={S.sectionTitle}>Invoices ({custInvoices(selCustomer.name).length})</div>
              {custInvoices(selCustomer.name).length === 0 ? <div style={{ color: T.textDim, fontSize: 13 }}>No invoices.</div> : (
                <table style={S.table}>
                  <thead><tr>{["Invoice #","Total","Paid","Balance","Status"].map(h => <th key={h} style={S.th}>{h}</th>)}</tr></thead>
                  <tbody>{custInvoices(selCustomer.name).map(inv => {
                    const bal = inv.total - inv.paid;
                    return <tr key={inv.id}>
                      <td style={{ ...S.td, color: T.accent, fontWeight: 700 }}>{inv.num}</td>
                      <td style={S.td}>{fmt(inv.total)}</td>
                      <td style={{ ...S.td, color: T.success }}>{fmt(inv.paid)}</td>
                      <td style={{ ...S.td, color: bal > 0 ? T.danger : T.success, fontWeight: 700 }}>{fmt(bal)}</td>
                      <td style={{ ...S.td, color: stColor[inv.status] }}>{inv.status}</td>
                    </tr>;
                  })}</tbody>
                </table>
              )}
            </div>
          )}

          <div className="tbl-wrap" style={{ marginTop: 12 }}>
            <table style={S.table}>
              <thead>
                <tr>{["Name","Phone","Email","Type","Total Spend","AR Owed","Notes","Actions"].map(h => <th key={h} style={S.th}>{h}</th>)}</tr>
              </thead>
              <tbody>
                {filtered.length === 0 && (
                  <tr><td colSpan={8} style={{ ...S.td, textAlign: "center", color: T.textDim }}>No customers yet — they auto-populate when you record orders.</td></tr>
                )}
                {filtered.map(c => {
                  const arOwed = custInvoices(c.name).reduce((s, i) => s + (i.total - i.paid), 0)
                    + custSales(c.name).reduce((s, sale) => {
                      const tot = orderTotal(sale);
                      const paid = sale.partialPaid !== "" && sale.partialPaid != null ? Number(sale.partialPaid) : tot;
                      return s + (tot - paid);
                    }, 0);
                  return (
                    <tr key={c.id} style={{ cursor: "pointer", background: selCust === c.id ? T.cardHover : "transparent" }}
                      onClick={() => setSelCust(selCust === c.id ? null : c.id)}>
                      <td style={{ ...S.td, fontWeight: 700, color: T.accent }}>{c.name}</td>
                      <td style={S.td}>{c.phone || "—"}</td>
                      <td style={S.td}>{c.email || "—"}</td>
                      <td style={S.td}>
                        <span style={{ background: classColor[c.classification] || T.info, color: c.classification === "VIP" ? "#000" : "#fff", borderRadius: 10, padding: "2px 10px", fontSize: 11 }}>{c.classification}</span>
                      </td>
                      <td style={{ ...S.td, color: T.success, fontWeight: 600 }}>{fmt(custTotalSpend(c.name))}</td>
                      <td style={{ ...S.td, color: arOwed > 0 ? T.danger : T.success, fontWeight: arOwed > 0 ? 700 : 400 }}>{arOwed > 0 ? fmt(arOwed) : "—"}</td>
                      <td style={{ ...S.td, fontSize: 12, color: T.textDim }}>{c.notes || "—"}</td>
                      <td style={S.td} onClick={e => e.stopPropagation()}>
                        <div style={{ display: "flex", gap: 4 }}>
                          <button style={{ ...S.btn("ghost"), fontSize: 11, padding: "2px 8px" }} onClick={() => { setForm({ name: c.name, phone: c.phone || "", email: c.email || "", classification: c.classification, notes: c.notes || "" }); setEditId(c.id); setAdding(true); }}>Edit</button>
                          <button style={{ ...S.btn("ghost"), fontSize: 11, padding: "2px 8px", color: T.danger }} onClick={() => deleteCustomer(c.id)}>Del</button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* ── INVOICES & AR ── */}
      {subTab === "invoices" && (
        <div>
          <div style={S.grid(4)}>
            <KpiCard label="AR Outstanding" value={fmt(totalAR)} color={T.danger} icon="⚠️" />
            <KpiCard label="Total Collected" value={fmt(totalPaid)} color={T.success} icon="✅" />
            <KpiCard label="Unpaid Invoices" value={invoices.filter(i => i.status === "Unpaid").length} color={T.warning} icon="📬" />
            <KpiCard label="Total Invoiced" value={fmt(invoices.reduce((s, i) => s + i.total, 0))} icon="📄" />
          </div>
          <div style={{ marginTop: 14 }}>
            <div className="tbl-wrap">
              <table style={S.table}>
                <thead>
                  <tr>{["Invoice #","Client","Issued","Due","Total","Paid","Balance","OD","Status","Documents","Action"].map(h => (
                    <th key={h} style={S.th}>{h}</th>
                  ))}</tr>
                </thead>
                <tbody>
                  {invoices.map((inv, i) => {
                    const bal = inv.total - inv.paid;
                    const od = daysOD(inv.due);
                    const evt = events.find(e => e.id === inv.eventId);
                    return (
                      <tr key={inv.id}>
                        <td style={{ ...S.td, fontWeight: 700, color: T.accent, whiteSpace: "nowrap" }}>{inv.num}</td>
                        <td style={{ ...S.td, fontWeight: 700 }}>{inv.client}</td>
                        <td style={{ ...S.td, whiteSpace: "nowrap" }}>{inv.issued}</td>
                        <td style={{ ...S.td, whiteSpace: "nowrap" }}>{inv.due}</td>
                        <td style={{ ...S.td, fontWeight: 600 }}>{fmt(inv.total)}</td>
                        <td style={{ ...S.td, color: T.success }}>{fmt(inv.paid)}</td>
                        <td style={{ ...S.td, fontWeight: 700, color: bal > 0 ? T.danger : T.success }}>{fmt(bal)}</td>
                        <td style={{ ...S.td, color: od > 0 ? T.danger : T.success, fontSize: 11 }}>{od > 0 ? `${od}d` : "—"}</td>
                        <td style={S.td}><span style={{ color: stColor[inv.status], fontWeight: 600 }}>{inv.status}</span></td>
                        <td style={S.td}>
                          {evt && (
                            <button style={{ ...S.btn("ghost"), fontSize: 11, padding: "2px 8px" }}
                              onClick={() => openDoc(`Invoice ${inv.num}`, buildInvoiceHTML(inv, evt, biz, logo))}>
                              Invoice
                            </button>
                          )}
                        </td>
                        <td style={S.td}>
                          {bal > 0 && (
                            <button style={{ ...S.btn("primary"), fontSize: 11, padding: "2px 8px" }}
                              onClick={() => {
                                const a = window.prompt(`Record payment for ${inv.client}\nBalance: ${fmt(bal)}\n\nEnter amount (USD):`);
                                if (a && !isNaN(Number(a))) recordPmt(i, a);
                              }}>
                              + Pmt
                            </button>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* ── AR OVERVIEW (Home Orders partial payments) ── */}
      {subTab === "ar" && (() => {
        const arSales = sales.filter(s => {
          if (!s.clientName) return false;
          const tot = orderTotal(s);
          const paid = s.partialPaid !== "" && s.partialPaid != null ? Number(s.partialPaid) : tot;
          return tot - paid > 0;
        });
        const totalRestAR = arSales.reduce((s, sale) => {
          const tot = orderTotal(sale);
          const paid = sale.partialPaid !== "" && sale.partialPaid != null ? Number(sale.partialPaid) : tot;
          return s + (tot - paid);
        }, 0);
        return (
          <div>
            <div style={S.grid(3)}>
              <KpiCard label="Home Orders AR" value={fmt(totalRestAR)} color={T.danger} icon="📦" />
              <KpiCard label="Catering AR" value={fmt(totalAR)} color={T.warning} icon="🎉" />
              <KpiCard label="Total Outstanding" value={fmt(totalRestAR + totalAR)} color={T.danger} icon="⚠️" />
            </div>
            <div style={S.sectionTitle}>Restaurant — Partial Payments Outstanding</div>
            {arSales.length === 0 ? (
              <div style={{ color: T.textDim, padding: 16 }}>No outstanding restaurant balances.</div>
            ) : (
              <div className="tbl-wrap">
                <table style={S.table}>
                  <thead><tr>{["Date","Client","Meal","Products","Order Total","Paid","Balance","Notes"].map(h => <th key={h} style={S.th}>{h}</th>)}</tr></thead>
                  <tbody>
                    {arSales.map(s => {
                      const tot = orderTotal(s);
                      const paid = s.partialPaid !== "" && s.partialPaid != null ? Number(s.partialPaid) : tot;
                      const bal = tot - paid;
                      return (
                        <tr key={s.id}>
                          <td style={S.td}>{s.date}</td>
                          <td style={{ ...S.td, fontWeight: 700 }}>{s.clientName}</td>
                          <td style={S.td}>{s.meal}</td>
                          <td style={S.td}>{s.plates}</td>
                          <td style={S.td}>{fmt(tot)}</td>
                          <td style={{ ...S.td, color: T.success }}>{fmt(paid)}</td>
                          <td style={{ ...S.td, color: T.danger, fontWeight: 700 }}>{fmt(bal)}</td>
                          <td style={{ ...S.td, fontSize: 12, color: T.textDim }}>{s.notes || "—"}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
            <div style={{ ...S.sectionTitle, marginTop: 18 }}>Catering — Unpaid / Partial Invoices</div>
            {invoices.filter(i => i.status !== "Paid" && i.status !== "Cancelled").length === 0 ? (
              <div style={{ color: T.textDim, padding: 16 }}>No outstanding catering invoices.</div>
            ) : (
              <div className="tbl-wrap">
                <table style={S.table}>
                  <thead><tr>{["Invoice #","Client","Due","Total","Paid","Balance","Status"].map(h => <th key={h} style={S.th}>{h}</th>)}</tr></thead>
                  <tbody>
                    {invoices.filter(i => i.status !== "Paid" && i.status !== "Cancelled").map(inv => {
                      const bal = inv.total - inv.paid;
                      return (
                        <tr key={inv.id}>
                          <td style={{ ...S.td, color: T.accent, fontWeight: 700 }}>{inv.num}</td>
                          <td style={{ ...S.td, fontWeight: 700 }}>{inv.client}</td>
                          <td style={S.td}>{inv.due}</td>
                          <td style={S.td}>{fmt(inv.total)}</td>
                          <td style={{ ...S.td, color: T.success }}>{fmt(inv.paid)}</td>
                          <td style={{ ...S.td, color: T.danger, fontWeight: 700 }}>{fmt(bal)}</td>
                          <td style={{ ...S.td, color: stColor[inv.status] }}>{inv.status}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        );
      })()}
    </div>
  );
}

// ─── VENDORS PAGE ─────────────────────────────────────────────────
function VendorsPage({ overheads, setOverheads }) {
  const [subTab, setSubTab] = useState("vendors");
  const [selVendor, setSelVendor] = useState(null);
  const [searchQ, setSearchQ] = useState("");
  const isMobile = useIsMobile();

  // Aggregate all overhead entries by vendor name
  const vendorMap = {};
  overheads.forEach(o => {
    const name = (o.vendor || "").trim();
    if (!name) return;
    if (!vendorMap[name]) {
      vendorMap[name] = { name, totalSpend: 0, entries: [], categories: new Set(), lastDate: "" };
    }
    vendorMap[name].totalSpend += Number(o.amount) || 0;
    vendorMap[name].entries.push(o);
    vendorMap[name].categories.add(o.category);
    if (!vendorMap[name].lastDate || o.date > vendorMap[name].lastDate) vendorMap[name].lastDate = o.date;
  });

  const vendors = Object.values(vendorMap)
    .map(v => ({ ...v, categories: [...v.categories] }))
    .sort((a, b) => b.totalSpend - a.totalSpend);

  const filtered = vendors.filter(v =>
    !searchQ || v.name.toLowerCase().includes(searchQ.toLowerCase())
  );

  const totalVendorSpend = vendors.reduce((s, v) => s + v.totalSpend, 0);
  const sel = selVendor ? vendors.find(v => v.name === selVendor) : null;

  return (
    <div>
      <div style={S.pageTitle}>🏪 Vendors & Expenses</div>

      {/* Sub-tabs */}
      <div style={{ ...S.row, gap: 6, marginBottom: 14, flexWrap: "wrap" }}>
        <button style={{ ...S.btn(subTab === "vendors" ? "primary" : "ghost"), fontSize: 13 }} onClick={() => { setSubTab("vendors"); setSelVendor(null); }}>🏪 Vendor Directory</button>
        <button style={{ ...S.btn(subTab === "expenses" ? "primary" : "ghost"), fontSize: 13 }} onClick={() => setSubTab("expenses")}>📋 All Expenses</button>
      </div>

      {subTab === "expenses" && <OverheadsPage overheads={overheads} setOverheads={setOverheads} />}

      {subTab === "vendors" && (
        <div>
          {/* KPIs */}
          <div style={S.grid(3)}>
            <KpiCard label="Total Vendors" value={vendors.length} icon="🏪" />
            <KpiCard label="Total Purchased" value={fmt(totalVendorSpend)} icon="💸" color={T.warning} />
            <KpiCard label="Avg per Vendor" value={vendors.length ? fmt(totalVendorSpend / vendors.length) : "$0"} icon="📊" color={T.info} />
          </div>

          {/* Search */}
          <div style={{ marginTop: 14, marginBottom: 10 }}>
            <input
              style={{ ...S.input, maxWidth: 260 }}
              placeholder="Search vendors…"
              value={searchQ}
              onChange={e => { setSearchQ(e.target.value); setSelVendor(null); }}
            />
          </div>

          {vendors.length === 0 ? (
            <div style={{ ...S.card, textAlign: "center", color: T.textMuted, padding: 32 }}>
              <div style={{ fontSize: 32, marginBottom: 8 }}>🏪</div>
              <div style={{ fontWeight: 700, marginBottom: 4 }}>No vendors yet</div>
              <div style={{ fontSize: 12 }}>Add a "Vendor / Payee" name when logging expenses — they'll appear here automatically.</div>
            </div>
          ) : sel ? (
            /* Vendor detail view */
            <div style={{ ...S.card, borderColor: T.accent }}>
              <div style={{ ...S.row, marginBottom: 14 }}>
                <div>
                  <div style={{ fontSize: 17, fontWeight: 800 }}>{sel.name}</div>
                  <div style={{ fontSize: 12, color: T.textMuted, marginTop: 2 }}>
                    {sel.categories.join(" · ")} · Last purchase {sel.lastDate}
                  </div>
                </div>
                <button style={{ ...S.btn("ghost"), fontSize: 12 }} onClick={() => setSelVendor(null)}>← Back</button>
              </div>

              {/* Summary row */}
              <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 10, marginBottom: 16 }}>
                {[
                  { label: "Total Spent", value: fmt(sel.totalSpend), color: T.danger },
                  { label: "Purchases", value: sel.entries.length, color: T.info },
                  { label: "Avg Purchase", value: fmt(sel.totalSpend / sel.entries.length), color: T.textMuted },
                ].map(({ label, value, color }) => (
                  <div key={label} style={{ background: T.surface, borderRadius: 8, padding: "10px 14px", border: `1px solid ${T.border}` }}>
                    <div style={{ fontSize: 10, color: T.textMuted, marginBottom: 3 }}>{label.toUpperCase()}</div>
                    <div style={{ fontSize: 18, fontWeight: 800, color }}>{value}</div>
                  </div>
                ))}
              </div>

              {/* Purchase history table */}
              <div style={{ fontSize: 12, fontWeight: 700, marginBottom: 8, color: T.textDim }}>PURCHASE HISTORY</div>
              <div className="tbl-wrap">
                <table style={S.table}>
                  <thead>
                    <tr>{["Date", "Category", "Description", "Type", "Amount"].map(h => <th key={h} style={S.th}>{h}</th>)}</tr>
                  </thead>
                  <tbody>
                    {[...sel.entries].sort((a, b) => b.date.localeCompare(a.date)).map((o, i) => (
                      <tr key={i}>
                        <td style={{ ...S.td, whiteSpace: "nowrap" }}>{o.date}</td>
                        <td style={S.td}>{o.category}</td>
                        <td style={{ ...S.td, fontWeight: 600 }}>{o.description}</td>
                        <td style={S.td}><span style={{ fontSize: 10, padding: "2px 6px", borderRadius: 4, background: o.entryType === "capex" ? T.catering + "22" : T.info + "22", color: o.entryType === "capex" ? T.catering : T.info, fontWeight: 700 }}>{(o.entryType || "opex").toUpperCase()}</span></td>
                        <td style={{ ...S.td, fontWeight: 700, color: T.danger, textAlign: "right" }}>{fmt(o.amount)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          ) : (
            /* Vendor directory list */
            <div style={{ display: "grid", gap: 8 }}>
              {filtered.map(v => {
                const pct = totalVendorSpend > 0 ? (v.totalSpend / totalVendorSpend) * 100 : 0;
                return (
                  <div
                    key={v.name}
                    style={{ ...S.card, cursor: "pointer", display: "flex", alignItems: "center", gap: 14 }}
                    onClick={() => setSelVendor(v.name)}
                  >
                    {/* Avatar */}
                    <div style={{ width: 42, height: 42, borderRadius: "50%", background: T.accent + "22", border: `2px solid ${T.accent}40`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>
                      🏪
                    </div>
                    {/* Info */}
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 2 }}>{v.name}</div>
                      <div style={{ fontSize: 11, color: T.textMuted, marginBottom: 5 }}>
                        {v.categories.slice(0, 3).join(" · ")}{v.categories.length > 3 ? ` +${v.categories.length - 3}` : ""} · {v.entries.length} purchase{v.entries.length !== 1 ? "s" : ""} · Last {v.lastDate}
                      </div>
                      {/* Spend bar */}
                      <div style={{ height: 4, borderRadius: 2, background: T.border, overflow: "hidden" }}>
                        <div style={{ height: "100%", width: `${pct}%`, background: T.accent, borderRadius: 2 }} />
                      </div>
                    </div>
                    {/* Spend */}
                    <div style={{ textAlign: "right", flexShrink: 0 }}>
                      <div style={{ fontSize: 15, fontWeight: 800, color: T.danger }}>{fmt(v.totalSpend)}</div>
                      <div style={{ fontSize: 10, color: T.textMuted }}>{pct.toFixed(1)}% of spend</div>
                    </div>
                    <div style={{ fontSize: 16, color: T.textMuted }}>›</div>
                  </div>
                );
              })}
              {filtered.length === 0 && (
                <div style={{ color: T.textMuted, fontSize: 13, textAlign: "center", padding: 24 }}>No vendors match "{searchQ}"</div>
              )}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ─── OVERHEAD EXPENSES PAGE ───────────────────────────────────────
function OverheadsPage({ overheads, setOverheads }) {
  const [subTab, setSubTab] = useState("list");
  const [adding, setAdding] = useState(false);
  const [editId, setEditId] = useState(null);
  const EMPTY_OH = {
    date: TODAY_ISO,
    category: "Rent & Premises",
    description: "",
    amount: "",
    frequency: "Monthly",
    vendor: "",
    entryType: "opex",
    paymentStatus: "paid",
    assetName: "",
  };
  const [form, setForm] = useState(EMPTY_OH);
  const [filterCat, setFilterCat] = useState("All");
  const [filterYear, setFilterYear] = useState(String(THIS_YEAR));
  const [filterMonth, setFilterMonth] = useState("All");
  const isMobile = useIsMobile();

  const years = [...new Set(overheads.map((o) => o.date.slice(0, 4)))]
    .sort()
    .reverse();
  const months = [
    "All",
    "01",
    "02",
    "03",
    "04",
    "05",
    "06",
    "07",
    "08",
    "09",
    "10",
    "11",
    "12",
  ];
  const monthNames = {
    "01": "Jan",
    "02": "Feb",
    "03": "Mar",
    "04": "Apr",
    "05": "May",
    "06": "Jun",
    "07": "Jul",
    "08": "Aug",
    "09": "Sep",
    10: "Oct",
    11: "Nov",
    12: "Dec",
    All: "All",
  };

  const filtered = overheads.filter((o) => {
    if (filterCat !== "All" && o.category !== filterCat) return false;
    if (filterYear !== "All" && !o.date.startsWith(filterYear)) return false;
    if (filterMonth !== "All" && o.date.slice(5, 7) !== filterMonth)
      return false;
    return true;
  });

  const totalFiltered = filtered.reduce((s, o) => s + Number(o.amount), 0);

  // Summary stats — only opex counts as "overhead expenses" for P&L
  const opexYTD = overheads.filter(
    (o) => o.date.startsWith("2026") && (o.entryType || "opex") === "opex"
  );
  const capexYTD = overheads.filter(
    (o) => o.date.startsWith("2026") && o.entryType === "capex"
  );
  const liabYTD = overheads.filter(
    (o) => o.date.startsWith("2026") && o.entryType === "liability_payment"
  );
  const totalYTD = opexYTD.reduce((s, o) => s + Number(o.amount), 0);
  const totalCapexYTD = capexYTD.reduce((s, o) => s + Number(o.amount), 0);
  const totalLiabYTD = liabYTD.reduce((s, o) => s + Number(o.amount), 0);
  const apTotal = overheads
    .filter((o) => o.paymentStatus === "unpaid")
    .reduce((s, o) => s + Number(o.amount), 0);
  const byCategory = {};
  opexYTD.forEach((o) => {
    byCategory[o.category] = (byCategory[o.category] || 0) + Number(o.amount);
  });
  const sortedCats = Object.entries(byCategory).sort((a, b) => b[1] - a[1]);

  const saveOverhead = () => {
    if (!form.description || !form.amount) return;
    const item = { ...form, amount: Number(form.amount) };
    if (editId != null) {
      setOverheads((prev) =>
        prev.map((o) => (o.id === editId ? { ...item, id: editId } : o))
      );
      setEditId(null);
    } else {
      setOverheads((prev) => [...prev, { ...item, id: Date.now() }]);
    }
    setAdding(false);
    setForm(EMPTY_OH);
  };
  const startEdit = (o) => {
    setForm({ ...o, amount: String(o.amount) });
    setEditId(o.id);
    setAdding(true);
    setSubTab("list");
  };
  const deleteItem = (id) =>
    setOverheads((prev) => prev.filter((o) => o.id !== id));

  const catColors = {
    "Rent & Premises": T.catering,
    Utilities: T.delivery,
    Personnel: T.accent,
    Transportation: T.restaurant,
    Marketing: T.info,
    Equipment: T.warning,
    Insurance: "#9A7AD4",
    "Professional Fees": "#4AD4C0",
    Subscriptions: "#D4A44A",
    Maintenance: "#7AD44A",
    Other: T.textMuted,
  };

  return (
    <div>
      <div style={S.pageTitle}>🏢 Expenses, Assets & Liabilities</div>
      <div style={S.subtitle}>
        Track operating expenses, asset purchases, and liability payments — each
        flows correctly to P&L, Balance Sheet & Cash Flows
      </div>

      <div style={{ display: "flex", gap: 3, marginBottom: 14 }}>
        {[
          ["list", "📋 Expense Ledger"],
          ["summary", "📊 Expenses Summary"],
        ].map(([t, label]) => (
          <button
            key={t}
            style={S.navBtn(subTab === t)}
            onClick={() => setSubTab(t)}
          >
            {label}
          </button>
        ))}
      </div>

      {/* ── SUMMARY SUB-TAB ── */}
      {subTab === "summary" && (
        <div>
          <div style={S.grid(3)}>
            <div style={S.card}>
              <div style={S.cardTitle}>Operating Expenses (YTD)</div>
              <div style={{ ...S.kpi, color: T.danger }}>{fmt(totalYTD)}</div>
              <div style={S.kpiSub}>Jan – Feb 2026 · hits P&L</div>
            </div>
            <div style={S.card}>
              <div style={S.cardTitle}>Asset Purchases (YTD)</div>
              <div style={{ ...S.kpi, color: T.warning }}>
                {fmt(totalCapexYTD)}
              </div>
              <div style={S.kpiSub}>
                {capexYTD.length} items · on Balance Sheet
              </div>
            </div>
            <div style={S.card}>
              <div style={S.cardTitle}>Accounts Payable (unpaid)</div>
              <div
                style={{ ...S.kpi, color: apTotal > 0 ? T.danger : T.success }}
              >
                {fmt(apTotal)}
              </div>
              <div style={S.kpiSub}>Across all entry types</div>
            </div>
          </div>

          <div style={{ ...S.grid(2), marginTop: 10 }}>
            <div style={S.card}>
              <div style={S.cardTitle}>By Category (YTD 2026)</div>
              {sortedCats.map(([cat, amt]) => (
                <div key={cat} style={{ marginBottom: 10 }}>
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "space-between",
                      marginBottom: 3,
                      alignItems: "center",
                    }}
                  >
                    <div
                      style={{ display: "flex", alignItems: "center", gap: 6 }}
                    >
                      <div
                        style={{
                          width: 8,
                          height: 8,
                          borderRadius: 2,
                          background: catColors[cat] || T.textMuted,
                          flexShrink: 0,
                        }}
                      />
                      <span style={{ fontSize: 11, fontWeight: 600 }}>
                        {cat}
                      </span>
                    </div>
                    <div style={{ textAlign: "right" }}>
                      <span
                        style={{
                          fontSize: 12,
                          fontWeight: 700,
                          color: catColors[cat] || T.text,
                        }}
                      >
                        {fmt(amt)}
                      </span>
                      <span
                        style={{
                          fontSize: 10,
                          color: T.textMuted,
                          marginLeft: 6,
                        }}
                      >
                        {totalYTD ? ((amt / totalYTD) * 100).toFixed(0) : 0}%
                      </span>
                    </div>
                  </div>
                  <PBar
                    pct={totalYTD ? (amt / totalYTD) * 100 : 0}
                    color={catColors[cat] || T.textMuted}
                  />
                </div>
