// Uses SheetJS loaded dynamically from CDN — no npm install needed
function useSheetJS() {
  const [ready, setReady] = useState(!!window.XLSX);
  useEffect(() => {
    if (window.XLSX) { setReady(true); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
    s.onload = () => setReady(true);
    document.head.appendChild(s);
  }, []);
  return ready;
}

function parseXLDate(v) {
  if (!v && v !== 0) return "";
  if (typeof v === "number") {
    const d = new Date(Math.round((v - 25569) * 86400000));
    return d.toISOString().slice(0, 10);
  }
  const s = String(v).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const d = new Date(s);
  return isNaN(d) ? s : d.toISOString().slice(0, 10);
}

function getSheet(wb, keyword) {
  const key = wb.SheetNames.find(n => n.toLowerCase().includes(keyword.toLowerCase()));
  if (!key) return [];
  // range:2 skips the two instruction rows so row 3 (0-indexed: 2) becomes the header row
  return window.XLSX.utils.sheet_to_json(wb.Sheets[key], { defval: "", range: 2 });
}

function parseWorkbook(wb) {
  const ts = Date.now();

  // Catalog
  const catalog = getSheet(wb, "Catalog").map((r, i) => ({
    id: ts + i,
    name: String(r["Item Name *"] || r["Item Name"] || "").trim(),
    catId: null,
    _catName: String(r["Category *"] || r["Category"] || "").trim(),
    unitType: String(r["Unit Type *"] || r["Unit Type"] || "Per item").trim(),
    price: Number(r["Price\n(USD) *"] || r["Price (USD) *"] || r["Price (USD)"] || r["Price"] || 0),
    costPerUnit: Number(r["Cost / Unit\n(USD)"] || r["Cost / Unit (USD)"] || r["Cost/Unit"] || 0),
    description: String(r["Description"] || "").trim(),
    tags: String(r["Tags\n(comma-sep)"] || r["Tags"] || "").split(",").map(t => t.trim()).filter(Boolean),
    photo: null,
  })).filter(r => r.name);

  // Meals
  const meals = getSheet(wb, "Meal").map((r, i) => ({
    id: ts + 10000 + i,
    name: String(r["Meal Name *"] || r["Meal Name"] || "").trim(),
    description: String(r["Description"] || "").trim(),
    price: Number(r["Price\n(USD) *"] || r["Price (USD) *"] || r["Price (USD)"] || r["Price"] || 0),
    category: String(r["Category"] || "Main").trim(),
    active: String(r["Active"] || "Yes").trim().toLowerCase() !== "no",
    laborCost: Number(r["Labor Cost\n(USD/plate)"] || r["Labor Cost (USD/plate)"] || r["Labor Cost"] || 0),
    availablePortions: Number(r["Available\nPortions"] || r["Available Portions"] || 0),
    ingredientLinks: [],
    otherCosts: [],
    photo: null,
  })).filter(r => r.name);

  // Inventory
  const inventory = getSheet(wb, "Inventory").map((r, i) => ({
    id: ts + 20000 + i,
    name: String(r["Item Name *"] || r["Item Name"] || "").trim(),
    category: String(r["Category *"] || r["Category"] || "Ingredient").trim(),
    unit: String(r["Unit\n(kg/L/pack…) *"] || r["Unit"] || "kg").trim(),
    stock: Number(r["Current Stock *"] || r["Current Stock"] || 0),
    reorderAt: Number(r["Reorder Level\n(min alert)"] || r["Reorder Level"] || r["Reorder At"] || 0),
    costPerUnit: Number(r["Cost / Unit\n(USD)"] || r["Cost / Unit (USD)"] || r["Cost/Unit"] || 0),
    usedPerPlate: Number(r["Used / Plate\n(optional)"] || r["Used / Plate"] || 0),
    linkedMeals: [],
  })).filter(r => r.name);

  // Events
  const events = getSheet(wb, "Event").map((r, i) => {
    const guests = Number(r["Guests *"] || r["Guests"] || 0);
    const pph = Number(r["Price/Head\n(USD)"] || r["Price/Head (USD)"] || r["Price/Head"] || 0);
    const addOns = Number(r["Add-Ons\n(USD)"] || r["Add-Ons (USD)"] || r["Add-Ons"] || 0);
    const discount = Number(r["Discount\n(USD)"] || r["Discount (USD)"] || r["Discount"] || 0);
    return {
      id: ts + 30000 + i,
      name: String(r["Event Name *"] || r["Event Name"] || "").trim(),
      clientName: String(r["Client Name *"] || r["Client Name"] || "").trim(),
      clientPhone: String(r["Client Phone"] || "").trim(),
      eventDate: parseXLDate(r["Event Date *\n(YYYY-MM-DD)"] || r["Event Date *"] || r["Event Date"] || ""),
      location: String(r["Location"] || "").trim(),
      eventType: String(r["Event Type *"] || r["Event Type"] || "Other").trim(),
      serviceStyle: String(r["Service Style *"] || r["Service Style"] || "Buffet").trim(),
      guests, pricePerHead: pph, addOns, discount,
      phase: String(r["Phase *"] || r["Phase"] || "Lead / Inquiry").trim(),
      notes: String(r["Notes"] || "").trim(),
      revenue: guests * pph + addOns - discount,
      costs: { inventory: 0, labor: 0, transport: 0, overhead: 0 },
      media: [],
    };
  }).filter(r => r.name);

  // Sales
  const sales = getSheet(wb, "Sales").map((r, i) => ({
    id: ts + 40000 + i,
    date: parseXLDate(r["Date *\n(YYYY-MM-DD)"] || r["Date *"] || r["Date"] || ""),
    meal: String(r["Meal Name *"] || r["Meal Name"] || "").trim(),
    plates: Number(r["Plates /\nUnits *"] || r["Plates / Units *"] || r["Products"] || 1),
    pricePerPlate: Number(r["Price / Plate\n(USD) *"] || r["Price / Plate (USD)"] || r["Price/Unit"] || 0),
    method: String(r["Payment\nMethod * \u25bc"] || r["Payment Method *"] || r["Payment Method"] || "Cash").trim(),
    type: String(r["Order Type *\n\u25bc"] || r["Order Type *"] || r["Order Type"] || "Delivery").trim(),
    deliveryFee: Number(r["Delivery Fee\n(USD)"] || r["Shipping Fee (USD)"] || r["Delivery Fee"] || 0),
    clientName: String(r["Client Name\n(delivery only)"] || r["Client Name"] || "").trim(),
    deliveryAddress: "",
  })).filter(r => r.meal);

  // Invoices
  const invoices = getSheet(wb, "Invoice").map((r, i) => {
    const total = Number(r["Total Amount\n(USD) *"] || r["Total Amount (USD)"] || r["Total Amount"] || 0);
    const paid = Number(r["Amount Paid\n(USD)"] || r["Amount Paid (USD)"] || r["Amount Paid"] || 0);
    const status = paid >= total && total > 0 ? "Paid" : paid > 0 ? "Partially Paid" : "Unpaid";
    return {
      id: ts + 50000 + i,
      num: String(r["Invoice # *"] || r["Invoice #"] || `INV-${THIS_YEAR}-${String(i+1).padStart(4,"0")}`).trim(),
      client: String(r["Client Name *"] || r["Client Name"] || "").trim(),
      clientPhone: String(r["Client Phone"] || "").trim(),
      issued: parseXLDate(r["Issue Date *\n(YYYY-MM-DD)"] || r["Issue Date *"] || r["Issue Date"] || ""),
      due: parseXLDate(r["Due Date *\n(YYYY-MM-DD)"] || r["Due Date *"] || r["Due Date"] || ""),
      total, paid, status,
      notes: String(r["Notes"] || "").trim(),
    };
  }).filter(r => r.client);

  // Overheads
  const overheads = getSheet(wb, "Overhead").map((r, i) => ({
    id: ts + 60000 + i,
    date: parseXLDate(r["Date *\n(YYYY-MM-DD)"] || r["Date *"] || r["Date"] || ""),
    entryType: String(r["Entry Type *\n\u25bc"] || r["Entry Type *"] || r["Entry Type"] || "opex").trim(),
    category: String(r["Category *\n\u25bc"] || r["Category *"] || r["Category"] || "Other").trim(),
    description: String(r["Description *"] || r["Description"] || "").trim(),
    amount: Number(r["Amount\n(USD) *"] || r["Amount (USD) *"] || r["Amount (USD)"] || r["Amount"] || 0),
    frequency: String(r["Frequency *\n\u25bc"] || r["Frequency *"] || r["Frequency"] || "One-time").trim(),
    vendor: String(r["Vendor / Supplier"] || r["Vendor"] || "").trim(),
    paymentStatus: String(r["Payment Status *\n\u25bc"] || r["Payment Status *"] || r["Payment Status"] || "paid").trim(),
    assetName: String(r["Asset Name\n(capex only)"] || r["Asset Name"] || "").trim(),
  })).filter(r => r.description);

  return { catalog, meals, inventory, events, sales, invoices, overheads };
}

function ImportModal({ onClose, onImport }) {
  const xlsxReady = useSheetJS();
  const fileRef = useRef();
  const [stage, setStage] = useState("idle");
  const [preview, setPreview] = useState(null);
  const [err, setErr] = useState("");
  const [counts, setCounts] = useState(null);

  const parse = (file) => {
    if (!file) return;
    if (!xlsxReady || !window.XLSX) { setErr("Parser still loading — please wait a moment and try again."); return; }
    setStage("parsing"); setErr("");
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const wb = window.XLSX.read(e.target.result, { type: "array", cellDates: false });
        const data = parseWorkbook(wb);
        setPreview(data);
        setCounts({
          "Catalog Items": data.catalog.length,
          "Meals": data.meals.length,
          "Inventory": data.inventory.length,
          "Catering Events": data.events.length,
          "Restaurant Sales": data.sales.length,
          "Invoices": data.invoices.length,
          "Overheads": data.overheads.length,
        });
        setStage("preview");
      } catch(e2) {
        setErr("Could not parse file: " + e2.message);
        setStage("error");
      }
    };
    reader.onerror = () => { setErr("Could not read file."); setStage("error"); };
    reader.readAsArrayBuffer(file);
  };

  const doImport = () => {
    if (!preview) return;
    setStage("importing");
    setTimeout(() => { onImport(preview); setStage("done"); }, 500);
  };

  const total = counts ? Object.values(counts).reduce((a, b) => a + b, 0) : 0;
  const populated = counts ? Object.entries(counts).filter(([, v]) => v > 0) : [];

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.85)", zIndex:3000, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
      <div style={{ background:T.card, border:`1px solid ${T.border}`, borderRadius:14, width:"100%", maxWidth:540, maxHeight:"92vh", display:"flex", flexDirection:"column", overflow:"hidden" }}>
        {/* Header */}
        <div style={{ padding:"14px 18px", borderBottom:`1px solid ${T.border}`, background:T.surface, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <div>
            <div style={{ fontWeight:800, fontSize:15 }}>⬆ Import Data from Excel</div>
            <div style={{ fontSize:11, color:T.textMuted, marginTop:2 }}>Upload the Delightful Meals and Drinks Import Template (.xlsx)</div>
          </div>
          <button style={{ background:"none", border:"none", color:T.textMuted, cursor:"pointer", fontSize:20, lineHeight:1 }} onClick={onClose}>×</button>
        </div>

        <div style={{ padding:18, overflowY:"auto", flex:1 }}>
          {/* Idle / Error */}
          {(stage === "idle" || stage === "error") && (
            <>
              {!xlsxReady && <div style={{ textAlign:"center", fontSize:11, color:T.textMuted, marginBottom:10 }}>⏳ Loading file parser…</div>}
              <div
                style={{ border:`2px dashed ${T.accent}`, borderRadius:10, padding:"32px 20px", textAlign:"center", cursor:xlsxReady?"pointer":"default", background:T.accentSoft, marginBottom:12 }}
                onClick={() => xlsxReady && fileRef.current.click()}
                onDragOver={e => e.preventDefault()}
                onDrop={e => { e.preventDefault(); const f = e.dataTransfer.files[0]; if(f) parse(f); }}
              >
                <div style={{ fontSize:40, marginBottom:10 }}>📊</div>
                <div style={{ fontWeight:700, fontSize:14, marginBottom:5 }}>Click to browse or drag & drop</div>
                <div style={{ fontSize:11, color:T.textMuted }}>DelightfulMeals_Import_Template.xlsx</div>
                <input ref={fileRef} type="file" accept=".xlsx,.xls" style={{ display:"none" }} onChange={e => e.target.files[0] && parse(e.target.files[0])} />
              </div>
              {err && <div style={{ background:`${T.danger}15`, border:`1px solid ${T.danger}40`, borderRadius:7, padding:"9px 12px", fontSize:12, color:T.danger, marginBottom:10 }}>⚠️ {err}</div>}
              <div style={{ background:T.surface, border:`1px solid ${T.border}`, borderRadius:8, padding:"10px 13px", fontSize:11, color:T.textMuted, lineHeight:1.75 }}>
                <div style={{ fontWeight:700, color:T.text, marginBottom:3 }}>⚠️ Before importing</div>
                This will <strong style={{ color:T.danger }}>replace all existing data</strong> for each sheet that has rows.
                Sheets with 0 rows will not be changed. Make sure you are using the official template.
              </div>
            </>
          )}

          {/* Parsing spinner */}
          {stage === "parsing" && (
            <div style={{ textAlign:"center", padding:"50px 0" }}>
              <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
              <div style={{ width:38, height:38, border:`3px solid ${T.accent}`, borderTopColor:"transparent", borderRadius:"50%", animation:"spin 0.7s linear infinite", margin:"0 auto 14px" }} />
              <div style={{ fontWeight:700 }}>Reading file…</div>
              <div style={{ fontSize:11, color:T.textMuted, marginTop:4 }}>Parsing all sheets</div>
            </div>
          )}

          {/* Preview */}
          {stage === "preview" && counts && (
            <>
              <div style={{ background:`${T.success}12`, border:`1px solid ${T.success}40`, borderRadius:8, padding:"10px 13px", fontSize:12, color:T.success, fontWeight:700, marginBottom:13 }}>
                ✅ File parsed — {total} record{total !== 1 ? "s" : ""} found across {populated.length} sheet{populated.length !== 1 ? "s" : ""}
              </div>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8, marginBottom:13 }}>
                {Object.entries(counts).map(([label, count]) => (
                  <div key={label} style={{ background:count > 0 ? T.accentSoft : T.surface, border:`1px solid ${count > 0 ? T.accent : T.border}`, borderRadius:8, padding:"9px 12px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                    <span style={{ fontSize:11, color:count > 0 ? T.text : T.textMuted }}>{label}</span>
                    <span style={{ fontSize:14, fontWeight:800, color:count > 0 ? T.accent : T.textDim }}>{count}</span>
                  </div>
                ))}
              </div>
              <div style={{ background:`${T.warning}12`, border:`1px solid ${T.warning}40`, borderRadius:8, padding:"9px 13px", fontSize:11, color:T.textMuted, lineHeight:1.7 }}>
                ⚠️ Clicking <strong style={{ color:T.text }}>Import Now</strong> will overwrite existing records in each populated sheet. Sheets with 0 rows will be left unchanged.
              </div>
            </>
          )}

          {/* Importing */}
          {stage === "importing" && (
            <div style={{ textAlign:"center", padding:"50px 0" }}>
              <div style={{ width:38, height:38, border:`3px solid ${T.accent}`, borderTopColor:"transparent", borderRadius:"50%", animation:"spin 0.7s linear infinite", margin:"0 auto 14px" }} />
              <div style={{ fontWeight:700 }}>Importing…</div>
            </div>
          )}

          {/* Done */}
          {stage === "done" && (
            <div style={{ textAlign:"center", padding:"36px 0" }}>
              <div style={{ fontSize:52, marginBottom:12 }}>✅</div>
              <div style={{ fontWeight:800, fontSize:16, marginBottom:6 }}>Import Complete!</div>
              <div style={{ fontSize:12, color:T.textMuted, marginBottom:20 }}>{total} records loaded into the platform.</div>
              <button style={{ ...S.btn("primary"), fontSize:13, padding:"9px 22px" }} onClick={onClose}>Close & View Data</button>
            </div>
          )}
        </div>

        {/* Footer */}
        {(stage === "idle" || stage === "error" || stage === "preview") && (
          <div style={{ padding:"11px 18px", borderTop:`1px solid ${T.border}`, display:"flex", justifyContent:"flex-end", gap:8 }}>
            <button style={S.btn("ghost")} onClick={onClose}>Cancel</button>
            {stage === "preview" && <button style={S.btn("primary")} onClick={doImport}>⬆ Import Now</button>}
          </div>
        )}
      </div>
    </div>
  );
}

// ─── MAIN APP ─────────────────────────────────────────────────────
const TABS = [
  { id: "dashboard", label: "📊 Dashboard" },
  { id: "catering", label: "🎉 Catering" },
  { id: "catalog", label: "📦 Catalog" },
  { id: "restaurant", label: "🏠 Home Orders" },
  { id: "customers", label: "👥 Customers" },
  { id: "vendors", label: "🏪 Vendors" },
  { id: "reports", label: "📑 Reports" },
  { id: "studio", label: "🤖 AI Studio", ownerOnly: true },
];

export default function App() {
  const [authed, setAuthed] = useState(() => !!loadSession());
  const [role, setRole] = useState(() => loadSession()?.role || "owner");
  const [authSynced, setAuthSynced] = useState(() => !!loadSession()); // skip sync if already logged in
  const isOwner = role === "owner" || role === "demo"; // demo gets full owner access
  const isDemo = role === "demo";
  const visibleTabs = isOwner ? TABS : TABS.filter(t => STAFF_TABS.includes(t.id) && !t.ownerOnly);
  const [tab, setTab] = useState(() => {
    const sess = loadSession();
    if (sess?.role === "staff") return "restaurant";
    return "dashboard";
  });
  // ── localStorage helpers (fallback / cache layer) ─────────────────
  const demoPrefix = isDemo ? "demo_" : "";
  function ls_get(key, fallback) {
    try {
      const raw = localStorage.getItem(demoPrefix + key);
      return raw !== null ? JSON.parse(raw) : fallback;
    } catch { return fallback; }
  }
  function ls_set(key, value) {
    try { localStorage.setItem(demoPrefix + key, JSON.stringify(value)); } catch {}
  }

  // ── Supabase persistence ───────────────────────────────────────────
  // Strategy: localStorage is used for instant startup (no flicker),
  // Supabase is the source of truth. On mount we fetch from Supabase
  // and overwrite local. On every state change we write to both.

  const DB_KEYS = [
    "cb_events","cb_sales","cb_invoices","cb_proposals",
    "cb_catalog","cb_catalog_cats","cb_inventory","cb_meals",
    "cb_batches","cb_overheads","cb_logo","cb_biz","cb_customers"
  ];

  const DEFAULTS = {
    cb_events: INIT_EVENTS,
    cb_sales: INIT_SALES,
    cb_invoices: INIT_INVOICES,
    cb_proposals: INIT_PROPOSALS,
    cb_catalog: CAT_ITEMS,
    cb_catalog_cats: CAT_CATS,
    cb_inventory: INIT_INVENTORY,
    cb_meals: INIT_MEALS,
    cb_batches: [],
    cb_overheads: INIT_OVERHEADS,
    cb_logo: { src: LOGO_SRC },
    cb_biz: INIT_BIZ,
    cb_customers: [],
  };

  // Debounce map to avoid flooding Supabase on rapid state changes
  const dbTimers = useRef({});
  function supa_set(key, value) {
    // Always write to localStorage immediately
    ls_set(key, value);
    // Debounce Supabase writes by 800ms
    const supaKey = demoPrefix + key;
    clearTimeout(dbTimers.current[supaKey]);
    dbTimers.current[supaKey] = setTimeout(async () => {
      try {
        await supabase.from("dm_store").upsert(
          { key: supaKey, data: value, updated_at: new Date().toISOString() },
          { onConflict: "key" }
        );
      } catch (e) {
        console.warn("Supabase write failed for", supaKey, e);
      }
    }, 800);
  }

  // ── Demo: seed localStorage on first visit (synchronous, before state init) ──
  // ── Demo: seed localStorage on first visit, then reload so state picks it up ──
  useEffect(() => {
    if (isDemo && !localStorage.getItem("demo_cb_sales")) {
      localStorage.setItem("demo_cb_events",       JSON.stringify(DEMO_DATA.events));
      localStorage.setItem("demo_cb_sales",         JSON.stringify(DEMO_DATA.sales));
      localStorage.setItem("demo_cb_invoices",      JSON.stringify(DEMO_DATA.invoices));
      localStorage.setItem("demo_cb_proposals",     JSON.stringify(DEMO_DATA.proposals));
      localStorage.setItem("demo_cb_catalog",       JSON.stringify(CAT_ITEMS));
      localStorage.setItem("demo_cb_catalog_cats",  JSON.stringify(CAT_CATS));
      localStorage.setItem("demo_cb_inventory",     JSON.stringify(DEMO_DATA.inv));
      localStorage.setItem("demo_cb_meals",         JSON.stringify(DEMO_DATA.meals));
      localStorage.setItem("demo_cb_batches",       JSON.stringify(DEMO_DATA.batches));
      localStorage.setItem("demo_cb_overheads",     JSON.stringify(DEMO_DATA.overheads));
      localStorage.setItem("demo_cb_biz",           JSON.stringify(DEMO_DATA.biz));
      localStorage.setItem("demo_cb_customers",     JSON.stringify(DEMO_DATA.customers));
      window.location.reload();
    }
  }, []); // run once on mount

  // State — initialized from localStorage for instant render
  const [events, setEvents] = useState(() => ls_get("cb_events", INIT_EVENTS));
  const [sales, setSales] = useState(() => ls_get("cb_sales", INIT_SALES));
  const [invoices, setInvoices] = useState(() => ls_get("cb_invoices", INIT_INVOICES));
  const [proposals, setProposals] = useState(() => ls_get("cb_proposals", INIT_PROPOSALS));
  const [proposalPrefillLines, setProposalPrefillLines] = useState(null);
  const [catalogItems, setCatalogItems] = useState(() => ls_get("cb_catalog", CAT_ITEMS));
  const [catalogCategories, setCatalogCategories] = useState(() => ls_get("cb_catalog_cats", CAT_CATS));
  const [inventory, setInventory] = useState(() => ls_get("cb_inventory", INIT_INVENTORY));
  const [meals, setMeals] = useState(() => ls_get("cb_meals", INIT_MEALS));
  const [batches, setBatches] = useState(() => ls_get("cb_batches", []));
  const [overheads, setOverheads] = useState(() => ls_get("cb_overheads", INIT_OVERHEADS));
  const [logo, setLogo] = useState(() => ls_get("cb_logo", { src: LOGO_SRC }));
  const [biz, setBiz] = useState(() => ls_get("cb_biz", INIT_BIZ));
  const [customers, setCustomers] = useState(() => ls_get("cb_customers", []));
  const [dbLoaded, setDbLoaded] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showImport, setShowImport] = useState(false);
  const isMobile = useIsMobile();

  // ── On mount: fetch latest data from Supabase (source of truth) ───
  useEffect(() => {
    async function loadFromSupabase() {
      try {
        const { data, error } = await supabase
          .from("dm_store")
          .select("key, data");
        if (error) { console.warn("Supabase load error:", error); setDbLoaded(true); return; }
        const map = {};
        (data || []).forEach(row => {
          // Strip demo prefix when building the map so keys match state names
          const k = isDemo ? (row.key.startsWith("demo_") ? row.key.slice(5) : null) : (!row.key.startsWith("demo_") ? row.key : null);
          if (k) map[k] = row.data;
        });

        // ── Demo seed: if demo login and no cloud data yet, seed from DEMO_DATA ──
        if (isDemo && Object.keys(map).length === 0) {
          setEvents(DEMO_DATA.events);         ls_set("cb_events",      DEMO_DATA.events);
          setSales(DEMO_DATA.sales);           ls_set("cb_sales",       DEMO_DATA.sales);
          setInvoices(DEMO_DATA.invoices);     ls_set("cb_invoices",    DEMO_DATA.invoices);
          setProposals(DEMO_DATA.proposals);   ls_set("cb_proposals",   DEMO_DATA.proposals);
          setCatalogItems(CAT_ITEMS);          ls_set("cb_catalog",     CAT_ITEMS);
          setCatalogCategories(CAT_CATS);      ls_set("cb_catalog_cats", CAT_CATS);
          setInventory(DEMO_DATA.inv);         ls_set("cb_inventory",   DEMO_DATA.inv);
          setMeals(DEMO_DATA.meals);           ls_set("cb_meals",       DEMO_DATA.meals);
          setBatches(DEMO_DATA.batches);       ls_set("cb_batches",     DEMO_DATA.batches);
          setOverheads(DEMO_DATA.overheads);   ls_set("cb_overheads",   DEMO_DATA.overheads);
          setBiz(DEMO_DATA.biz);               ls_set("cb_biz",         DEMO_DATA.biz);
          setCustomers(DEMO_DATA.customers);   ls_set("cb_customers",   DEMO_DATA.customers);
          setDbLoaded(true);
          return;
        }

        // Apply Supabase data — overrides localStorage with cloud truth
        if (map["cb_events"])        { setEvents(map["cb_events"]);               ls_set("cb_events", map["cb_events"]); }
        if (map["cb_sales"])         { setSales(map["cb_sales"]);                  ls_set("cb_sales", map["cb_sales"]); }
        if (map["cb_invoices"])      { setInvoices(map["cb_invoices"]);            ls_set("cb_invoices", map["cb_invoices"]); }
        if (map["cb_proposals"])     { setProposals(map["cb_proposals"]);          ls_set("cb_proposals", map["cb_proposals"]); }
        if (map["cb_catalog"])       { setCatalogItems(map["cb_catalog"]);         ls_set("cb_catalog", map["cb_catalog"]); }
        if (map["cb_catalog_cats"])  { setCatalogCategories(map["cb_catalog_cats"]); ls_set("cb_catalog_cats", map["cb_catalog_cats"]); }
        if (map["cb_inventory"])     { setInventory(map["cb_inventory"]);          ls_set("cb_inventory", map["cb_inventory"]); }
        if (map["cb_meals"])         { setMeals(map["cb_meals"]);                  ls_set("cb_meals", map["cb_meals"]); }
        if (map["cb_batches"])       { setBatches(map["cb_batches"]);              ls_set("cb_batches", map["cb_batches"]); }
        if (map["cb_overheads"])     { setOverheads(map["cb_overheads"]);          ls_set("cb_overheads", map["cb_overheads"]); }
        if (map["cb_logo"])          { setLogo(map["cb_logo"]);                    ls_set("cb_logo", map["cb_logo"]); }
        if (map["cb_biz"])           { setBiz(map["cb_biz"]);                      ls_set("cb_biz", map["cb_biz"]); }
        if (map["cb_customers"])     { setCustomers(map["cb_customers"]);          ls_set("cb_customers", map["cb_customers"]); }
      } catch(e) {
        console.warn("Supabase fetch failed, using localStorage:", e);
      }
      setDbLoaded(true);
    }
    loadFromSupabase();
  }, []);

  // ── Sync every state change to Supabase + localStorage ───────────
  useEffect(() => { supa_set("cb_events", events); }, [events]);
  useEffect(() => { supa_set("cb_sales", sales); }, [sales]);
  useEffect(() => { supa_set("cb_invoices", invoices); }, [invoices]);
  useEffect(() => { supa_set("cb_proposals", proposals); }, [proposals]);
  useEffect(() => { supa_set("cb_catalog", catalogItems); }, [catalogItems]);
  useEffect(() => { supa_set("cb_catalog_cats", catalogCategories); }, [catalogCategories]);
  useEffect(() => { supa_set("cb_inventory", inventory); }, [inventory]);
  useEffect(() => { supa_set("cb_meals", meals); }, [meals]);
  useEffect(() => { supa_set("cb_batches", batches); }, [batches]);
  useEffect(() => { supa_set("cb_overheads", overheads); }, [overheads]);
  useEffect(() => { supa_set("cb_logo", logo); }, [logo]);
  useEffect(() => { supa_set("cb_biz", biz); }, [biz]);
  useEffect(() => { supa_set("cb_customers", customers); }, [customers]);

  // ── Migrate: merge new CAT_ITEMS into live catalog + fix categoryId → catId ──
  useEffect(() => {
    if (!dbLoaded || isDemo) return;
    setCatalogItems(prev => {
      // Step 1: fix any items that were stored with categoryId instead of catId
      let repaired = prev.map(i => {
        if (i.categoryId !== undefined && i.catId === undefined) {
          const { categoryId, ...rest } = i;
          return { ...rest, catId: categoryId };
        }
        return i;
      });
      // Step 2: merge in any new CAT_ITEMS not yet in the catalog
      const existingIds = new Set(repaired.map(i => i.id));
      const toAdd = CAT_ITEMS.filter(i => !existingIds.has(i.id));
      if (toAdd.length === 0 && repaired.length === prev.length &&
          repaired.every((r, i) => r === prev[i])) return prev;
      return [...repaired, ...toAdd];
    });
  }, [dbLoaded]); // run once after data loads

  // Reconcile customers from all orders + events whenever data loads or changes
  useEffect(() => {
    if (!dbLoaded) return;
    setCustomers(prev => {
      const updated = [...prev];
      const nameIndex = new Map(prev.map((c, i) => [c.name.toLowerCase(), i]));
      let changed = false;
      [...sales, ...events].forEach(r => {
        const name = (r.clientName || "").trim();
        if (!name) return;
        const key = name.toLowerCase();
        const phone = (r.clientPhone || "").trim();
        if (nameIndex.has(key)) {
          const i = nameIndex.get(key);
          if (!updated[i].phone && phone) {
            updated[i] = { ...updated[i], phone };
            changed = true;
          }
        } else {
          const newC = { id: Date.now() + updated.length + Math.floor(Math.random() * 9999), name, phone, email: "", classification: "Regular", notes: "", createdAt: r.date || r.eventDate || TODAY_ISO };
          updated.push(newC);
          nameIndex.set(key, updated.length - 1);
          changed = true;
        }
      });
      return changed ? updated : prev;
    });
  }, [dbLoaded, sales, events]);

  const handleLogout = () => {
    clearSession();
    setAuthed(false);
  };

  const handleImport = (data) => {
    if (data.catalog.length)    setCatalogItems(data.catalog);
    if (data.meals.length)      setMeals(data.meals);
    if (data.inventory.length)  setInventory(data.inventory);
    if (data.events.length)     setEvents(data.events);
    if (data.sales.length)      setSales(data.sales);
    if (data.invoices.length)   setInvoices(data.invoices);
    if (data.overheads.length)  setOverheads(data.overheads);
  };

  // ── Pre-login: pull cb_auth_v2 from Supabase so any device can log in ──
  useEffect(() => {
    if (authed) return; // already logged in, no need
    async function syncAuth() {
      try {
        const { data } = await supabase
          .from("dm_store")
          .select("data")
          .eq("key", "cb_auth_v2")
          .single();
        if (data?.data) {
          // Merge cloud auth into localStorage — cloud wins for owner/staff credentials
          const local = (() => { try { return JSON.parse(localStorage.getItem(AUTH_KEY)) || {}; } catch { return {}; } })();
          const merged = { ...local, ...data.data };
          localStorage.setItem(AUTH_KEY, JSON.stringify(merged));
        }
      } catch { /* offline or no row yet — use localStorage as-is */ }
      setAuthSynced(true);
    }
    syncAuth();
  }, []); // run once on mount

  if (!authed) {
    if (!authSynced) {
      // Brief loading state while we pull credentials from Supabase
      return (
        <div style={{ background: "#0e0e0e", minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 14 }}>
          <img src={LOGO_SRC} alt="Delightful Meals" style={{ width: 90, height: 90, objectFit: "contain", opacity: 0.9 }} />
          <div style={{ width: 28, height: 28, border: "3px solid #333", borderTopColor: "#E8C547", borderRadius: "50%", animation: "spin 0.75s linear infinite" }} />
          <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
        </div>
      );
    }
    return <LoginScreen onLogin={(r) => {
      setRole(r);
      if (r === "staff") setTab("restaurant");
      setAuthed(true);
    }} />;
  }

  return (
    <div style={S.app}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:opsz,wght@9..40,400;9..40,500;9..40,600;9..40,700;9..40,800&display=swap');
        *{box-sizing:border-box;margin:0;padding:0}
        ::-webkit-scrollbar{width:4px;height:4px}
        ::-webkit-scrollbar-track{background:#141414}
        ::-webkit-scrollbar-thumb{background:#2a2a2a;border-radius:3px}
        input:focus,select:focus,textarea:focus{border-color:#E8C547!important;box-shadow:0 0 0 2px rgba(232,197,71,0.07)!important;outline:none}
        button:hover{opacity:0.80}
        tr:hover td{background:rgba(255,255,255,0.015)}
        textarea{background:#141414;border:1px solid #252525;border-radius:6px;padding:6px 9px;color:#EDEBE4;font-size:12px;width:100%;box-sizing:border-box;font-family:inherit}
        input[type=number]::-webkit-inner-spin-button{opacity:0.5}
        /* ── MOBILE RESPONSIVE ── */
        @media(max-width:767px){
          /* Prevent iOS zoom on inputs */
          input,select,textarea{font-size:16px!important}
          /* All fixed-column grids collapse on mobile */
          [style*="repeat(3"],[style*="repeat(4"],[style*="repeat(5"]{
            grid-template-columns:1fr!important;
          }
          /* 2-col grids stay 2-col unless very narrow */
          [style*="repeat(2"]{
            grid-template-columns:1fr 1fr!important;
          }
          /* Tables scroll horizontally */
          table{min-width:480px}
          /* Cards get less padding */
          [style*="padding: 14"]{padding:10px!important}
          /* Sticky sidebar panels go full-width */
          [style*="360px"]{grid-template-columns:1fr!important}
          [style*="position: sticky"]{position:static!important;max-height:none!important}
          /* Ensure buttons are tappable */
          button{min-height:34px}
        }
        /* Wrap all table containers */
        .tbl-wrap{overflow-x:auto;-webkit-overflow-scrolling:touch}
      `}</style>

      {showSettings && isOwner && (
        <SettingsModal
          biz={biz}
          setBiz={setBiz}
          logo={logo}
          onClose={() => setShowSettings(false)}
        />
      )}
      {showImport && isOwner && (
        <ImportModal
          onClose={() => setShowImport(false)}
          onImport={handleImport}
        />
      )}

      {/* ── TOPBAR ── */}
      {isMobile ? (
        <div
          style={{
            background: T.surface,
            borderBottom: `1px solid ${T.border}`,
            padding: "0 12px",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            height: 48,
            flexShrink: 0,
          }}
        >
          <div
            style={{
              fontSize: 15,
              fontWeight: 800,
              color: T.accent,
              letterSpacing: -0.3,
            }}
          >
            <img
              src={logo?.src || LOGO_SRC}
              alt="Cookie's Bites"
              style={{ height: 36, maxWidth: 120, objectFit: "contain" }}
            />
          </div>
          <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
            {isDemo && (
              <span style={{
                fontSize: 9, fontWeight: 800, letterSpacing: 0.8,
                color: "#fff", background: "#e67e22",
                border: "1px solid #e67e2260",
                borderRadius: 20, padding: "1px 8px",
              }}>⚡ DEMO</span>
            )}
            {isDemo && (
              <button
                style={{ ...S.btn("ghost"), fontSize: 10, padding: "3px 8px", color: "#e67e22", border: "1px solid #e67e2250" }}
                title="Reset all demo data back to sample defaults"
                onClick={() => {
                  if (!window.confirm("Reset all demo data to sample defaults? This cannot be undone.")) return;
                  const keys = ["cb_events","cb_sales","cb_invoices","cb_proposals","cb_catalog","cb_catalog_cats","cb_inventory","cb_meals","cb_batches","cb_overheads","cb_logo","cb_biz","cb_customers"];
                  keys.forEach(k => localStorage.removeItem("demo_" + k));
                  window.location.reload();
                }}
              >🔄 Reset</button>
            )}
            {isOwner && !isDemo && (
              <button
                style={{ ...S.btn("ghost"), fontSize: 10, padding: "3px 7px", color: T.accent, border: `1px solid ${T.accent}50` }}
                onClick={() => setShowImport(true)}
              >
                ⬆
              </button>
            )}
            {isOwner && (
              <button
                style={{ ...S.btn("ghost"), fontSize: 11, padding: "4px 8px" }}
                onClick={() => setShowSettings(true)}
              >
                ⚙️
              </button>
            )}
            <button
              title="Sign out"
              style={{ ...S.btn("ghost"), fontSize: 11, padding: "4px 8px", color: T.textMuted }}
              onClick={handleLogout}
            >
              ⏻
            </button>
          </div>
        </div>
      ) : (
        <div style={S.topbar}>
          <LogoArea
            logo={logo}
            setLogo={setLogo}
            biz={biz}
            onSettings={isOwner ? () => setShowSettings(true) : null}
          />
          <div
            style={{
              width: 1,
              height: 18,
              background: T.border,
              flexShrink: 0,
            }}
          />
          <div style={S.nav}>
            {visibleTabs.map((t) => (
              <button
                key={t.id}
                style={S.navBtn(tab === t.id)}
                onClick={() => setTab(t.id)}
              >
                {t.label}
              </button>
            ))}
          </div>
          <div style={{ display: "flex", gap: 8, alignItems: "center", flexShrink: 0 }}>
            {isDemo ? (
              <span style={{
                fontSize: 9, fontWeight: 800, letterSpacing: 0.8,
                color: "#fff", background: "#e67e22",
                border: "1px solid #e67e2260",
                borderRadius: 20, padding: "2px 8px", whiteSpace: "nowrap",
              }}>⚡ DEMO MODE</span>
            ) : (
            <span style={{
              fontSize: 9, fontWeight: 700, letterSpacing: 0.5,
              color: isOwner ? T.accent : T.info,
              background: isOwner ? T.accentSoft : `${T.info}18`,
              border: `1px solid ${isOwner ? T.accent : T.info}40`,
              borderRadius: 20, padding: "2px 8px", whiteSpace: "nowrap",
            }}>{isOwner ? "👑 Owner" : "👤 Staff"}</span>
            )}
            <div style={{ fontSize: 10, color: T.textMuted, whiteSpace: "nowrap" }}>
              📍{biz.city} · {TODAY_LABEL}
            </div>
            {isOwner && (
              <button
                title="Import data from Excel"
                style={{ ...S.btn("ghost"), fontSize: 11, padding: "4px 10px", color: T.accent, border: `1px solid ${T.accent}50` }}
                onClick={() => setShowImport(true)}
              >
                ⬆ Import
              </button>
            )}
            <button
              title="Sign out"
              style={{ ...S.btn("ghost"), fontSize: 11, padding: "4px 10px" }}
              onClick={handleLogout}
            >
              ⏻ Sign Out
            </button>
          </div>
        </div>
      )}

      {/* ── MAIN CONTENT ── */}
      <div style={isMobile ? S.mainMobile : S.main}>
        {tab === "dashboard" && (
          <Dashboard
            events={events}
            sales={sales}
            invoices={invoices}
            catalogItems={catalogItems}
            overheads={overheads}
            inventory={inventory}
            meals={meals}
          />
        )}
        {tab === "catering" && (
          <CateringPage
            events={events}
            setEvents={setEvents}
            proposals={proposals}
            setProposals={setProposals}
            invoices={invoices}
            setInvoices={setInvoices}
            inventory={inventory}
            logo={logo}
            biz={biz}
            customers={customers}
            setCustomers={setCustomers}
            catalogItems={catalogItems}
            catalogCategories={catalogCategories}
            proposalPrefillLines={proposalPrefillLines}
            clearProposalPrefill={() => setProposalPrefillLines(null)}
          />
        )}
        {tab === "catalog" && (
          <CatalogPage
            categories={catalogCategories}
            setCategories={setCatalogCategories}
            items={catalogItems}
            setItems={setCatalogItems}
            meals={meals}
            logo={logo}
            biz={biz}
            onCreateProposalFromCatalog={(lines) => {
              setProposalPrefillLines(lines);
              setTab("catering");
